-- Schema for Domain: inventory | Business: Airlines | Version: v1_ecm
-- Generated on: 2026-05-07 12:58:06

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `airlines_ecm`.`inventory` COMMENT 'Flight inventory and seat capacity availability management â€” the airlines sellable stock. Owns fare class buckets, seat availability by cabin, overbooking controls, codeshare inventory allocations, and real-time availability snapshots consumed by GDS and direct channels. Directly feeds revenue management yield optimization. Aligns with Amadeus AltĂ©a Inventory.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`flight_inventory` (
    `flight_inventory_id` BIGINT COMMENT 'Unique surrogate identifier for the flight inventory record representing the sellable seat inventory for a specific flight-date combination in the Amadeus AltĂ©a Inventory system.',
    `aircraft_id` BIGINT COMMENT 'Foreign key linking to fleet.aircraft. Business justification: Flight inventory is opened on a specific tail number for each departure. Operations Control Center assigns aircraft to flights; inventory management needs tail number for MEL item applicability, actua',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Marketing campaigns target specific flights for promotional fares and seat sales. Campaign managers track which inventory is being promoted for performance measurement and ROI analysis. Essential for ',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Flight operations are cost centers in airline accounting. CASK (Cost per Available Seat Kilometer) calculations require linking flight inventory to cost centers for profitability analysis and manageme',
    `fleet_assignment_id` BIGINT COMMENT 'Foreign key linking to route.route_fleet_assignment. Business justification: Fleet assignment determines aircraft type, seat configuration, and cabin class capacity that inventory must control. Revenue management bucket authorization, overbooking limits, and codeshare allocati',
    `flight_number_id` BIGINT COMMENT 'Foreign key linking to route.flight_number. Business justification: Flight inventory controls real-time seat availability for specific flight numbers defined in route planning. Revenue management, codeshare allocation, and GDS distribution all require linking daily in',
    `operating_certificate_id` BIGINT COMMENT 'Foreign key linking to compliance.operating_certificate. Business justification: Every flight operates under a specific air operator certificate (AOC) that authorizes the carriers operations. Flight inventory must reference the certificate authorizing that flights operation for ',
    `operational_approval_id` BIGINT COMMENT 'Foreign key linking to compliance.operational_approval. Business justification: Flights requiring special operational approvals (ETOPS, CAT III, RNP AR) must reference the specific approval authorizing that operation. Critical for dispatch validation, crew qualification verificat',
    `promotional_fare_id` BIGINT COMMENT 'Foreign key linking to marketing.promotional_fare. Business justification: Promotional fares are allocated against specific flight inventory for capacity control and seat cap enforcement. Airlines track promotional seat utilization per flight for yield management. Essential ',
    `route_id` BIGINT COMMENT 'FK to route.route.route_id â€” Flight inventory must reference the route for network-level availability queries, codeshare allocation management, and seasonal capacity planning.',
    `scheduled_flight_id` BIGINT COMMENT 'Reference to the scheduled flight leg for which this inventory record is maintained. Links to the flight master entity in the flight operations domain.',
    `seasonal_schedule_id` BIGINT COMMENT 'Foreign key linking to route.seasonal_schedule. Business justification: Flight inventory operationalizes a specific seasonal schedule template. Linking inventory to seasonal_schedule enables variance analysis (planned vs actual capacity), schedule change impact assessment',
    `altea_inventory_key` STRING COMMENT 'Native primary key or reference identifier assigned by the Amadeus AltĂ©a Inventory system to this flight inventory record. Used for system-of-record traceability and reconciliation between the lakehouse Silver layer and the operational PSS.',
    `authorized_capacity` STRING COMMENT 'Revenue management-approved seat count authorized for sale on this flight-date, which may differ from total physical capacity due to operational holds, crew seat requirements, or regulatory restrictions. This is the effective inventory ceiling used by Sabre AirVision Revenue Management.',
    `availability_snapshot_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent real-time availability snapshot broadcast to GDS and direct booking channels. Reflects the point-in-time at which seats_available and fare class bucket statuses were last synchronized with Amadeus AltĂ©a.',
    `booking_curve_day` STRING COMMENT 'Number of days prior to departure at which this inventory snapshot was captured, representing the position on the booking curve (e.g., 90, 60, 30, 14, 7, 1). Used by Sabre AirVision Revenue Management for demand forecasting and fare class optimization.',
    `business_class_capacity` STRING COMMENT 'Total number of seats allocated to the Business Class cabin on this flight-date. Reflects the aircraft configuration and any cabin reconfiguration applied for this specific flight.',
    `channel_restriction_code` STRING COMMENT 'Code indicating any channel-specific sales restrictions applied to this flight inventory (e.g., DIRECT_ONLY for web/app exclusive fares, GDS_BLOCKED for GDS channel closure, NDC_ONLY for IATA NDC channel exclusivity). Controls distribution channel access to inventory.',
    `codeshare_indicator` BOOLEAN COMMENT 'Flag indicating whether this flight inventory record includes codeshare seat allocations from partner airlines. When true, a portion of the authorized capacity is reserved for codeshare partner bookings under interline ticketing agreements.',
    `codeshare_seats_allocated` STRING COMMENT 'Number of seats within the authorized capacity ring-fenced for codeshare partner airline bookings on this flight-date. Managed under bilateral codeshare agreements and tracked separately from own-metal inventory for revenue accounting and BSP settlement.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this flight inventory record was first created in the Amadeus AltĂ©a Inventory system, typically at the time of schedule publication or inventory initialization for the flight-date.',
    `departure_date` DATE COMMENT 'Scheduled local departure date of the flight leg at the origin station. Together with flight_number, forms the primary business key for inventory lookup by GDS and booking channels.',
    `destination_airport_code` STRING COMMENT 'Three-letter IATA airport code for the arrival station of this flight leg (e.g., LAX, CDG). Used to identify the inventory leg destination in route network and GDS availability queries.. Valid values are `^[A-Z]{3}$`',
    `economy_capacity` STRING COMMENT 'Total number of seats allocated to the Economy Class cabin on this flight-date. Typically the largest cabin and primary driver of load factor and revenue management decisions.',
    `equipment_change_indicator` BOOLEAN COMMENT 'Flag indicating whether the aircraft type assigned to this flight-date has been changed from the originally scheduled equipment. Equipment changes may alter cabin configuration, total capacity, and fare class bucket allocations requiring inventory rebalancing.',
    `fare_class_bucket_config` STRING COMMENT 'Serialized representation of the active fare class bucket (booking class) configuration for this flight-date, listing each IATA booking class code and its authorized seat allocation (e.g., Y:20,B:15,M:10,Q:5). Managed by Sabre AirVision Revenue Management and consumed by Amadeus AltĂ©a for availability control.',
    `first_class_capacity` STRING COMMENT 'Total number of seats allocated to the First Class cabin on this flight-date. Reflects the aircraft configuration and any cabin reconfiguration applied for this specific flight.',
    `flight_number` STRING COMMENT 'IATA-format airline designator and numeric flight number (e.g., AA101) identifying the marketed flight for which inventory is being managed. Used by GDS and direct channels to query availability.. Valid values are `^[A-Z]{2}[0-9]{1,4}$`',
    `gds_availability_code` STRING COMMENT 'Single-letter availability status code broadcast to Global Distribution Systems (GDS) representing the highest open booking class on this flight-date (e.g., Y for full availability, L for restricted availability). Conforms to IATA availability message standards.. Valid values are `^[A-Z]$`',
    `group_seats_held` STRING COMMENT 'Number of seats currently held under group booking reservations (typically 10+ passengers under a single PNR group) on this flight-date. Group holds reduce available inventory for individual bookings and are subject to group ticketing deadlines.',
    `interline_seats_allocated` STRING COMMENT 'Number of seats allocated for interline ticketing partner bookings on this flight-date under IATA interline agreements. Distinct from codeshare allocations and tracked for ARC/BSP proration and revenue accounting.',
    `inventory_control_mode` STRING COMMENT 'Indicates whether inventory management for this flight-date is operating under MANUAL (revenue analyst override), AUTOMATED (Sabre AirVision algorithmic control), or HYBRID (automated with manual overrides) mode. Affects how fare class bucket changes are applied.. Valid values are `MANUAL|AUTOMATED|HYBRID`',
    `inventory_status` STRING COMMENT 'Current operational status of the flight inventory record in Amadeus AltĂ©a. OPEN indicates seats are available for sale; CLOSED indicates no further sales permitted; WAITLIST indicates demand exceeds supply and waitlist is active; SUSPENDED indicates temporary hold on sales; CANCELLED indicates the flight has been cancelled and inventory is frozen.. Valid values are `OPEN|CLOSED|WAITLIST|SUSPENDED|CANCELLED`',
    `last_seat_availability_date` DATE COMMENT 'Date on which the last available seat on this flight-date was sold or the inventory was closed. Used for post-departure revenue analysis and booking curve benchmarking.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this flight inventory record, including any changes to seat counts, fare class buckets, overbooking parameters, or inventory status. Critical for real-time availability synchronization with GDS.',
    `load_factor_pct` DECIMAL(18,2) COMMENT 'Current load factor expressed as a percentage, calculated as seats_sold divided by authorized_capacity multiplied by 100. A key revenue management KPI representing the proportion of available seat capacity that has been sold. Used by Sabre AirVision for yield optimization decisions.',
    `operational_seats_held` STRING COMMENT 'Number of seats withheld from sale for operational purposes including deadhead crew positioning, airline staff travel, and aircraft ferry requirements. These seats are excluded from the sellable inventory pool.',
    `origin_airport_code` STRING COMMENT 'Three-letter IATA airport code for the departure station of this flight leg (e.g., JFK, LHR). Used to identify the inventory leg origin in route network and GDS availability queries.. Valid values are `^[A-Z]{3}$`',
    `overbooking_factor` DECIMAL(18,2) COMMENT 'Revenue management-approved overbooking multiplier expressed as a percentage above physical capacity (e.g., 105.00 means 5% overbooking allowed). Set by Sabre AirVision Revenue Management based on historical no-show and cancellation rates to maximize load factor while managing denied boarding risk.',
    `overbooking_limit` STRING COMMENT 'Absolute maximum number of bookings permitted on this flight-date including the overbooking allowance. Computed from authorized_capacity multiplied by overbooking_factor and used as the hard ceiling in the Amadeus AltĂ©a booking engine.',
    `premium_economy_capacity` STRING COMMENT 'Total number of seats allocated to the Premium Economy cabin on this flight-date. Nullable for aircraft configurations that do not include a Premium Economy cabin.',
    `revenue_management_class` STRING COMMENT 'Revenue management classification assigned by Sabre AirVision to this flight-date based on demand forecast, booking curve position, and competitive pricing environment. Drives automated fare class bucket opening and closing decisions for yield optimization.. Valid values are `LOW|MID|HIGH|PEAK|DISTRESSED`',
    `schedule_change_indicator` BOOLEAN COMMENT 'Flag indicating whether this flight-date has undergone a schedule change (time, equipment, or routing modification) since the original inventory record was created. Schedule changes may trigger IROP (Irregular Operations) rebooking workflows and inventory reallocation.',
    `seats_available` STRING COMMENT 'Current number of seats available for sale across all cabins on this flight-date, calculated as authorized_capacity minus seats_sold minus overbooking_buffer. This is the real-time availability figure broadcast to GDS and direct booking channels.',
    `seats_sold` STRING COMMENT 'Total number of confirmed seat bookings (Pax) across all cabins and fare classes on this flight-date. Updated in real-time as reservations are created, modified, or cancelled in the Amadeus AltĂ©a Reservation system.',
    `total_capacity` STRING COMMENT 'Total number of physical seats available on the aircraft for this flight-date combination across all cabins. Derived from the aircraft configuration assigned to the flight and represents the maximum sellable inventory ceiling.',
    `waitlist_count` STRING COMMENT 'Current number of passengers on the waitlist for this flight-date when inventory_status is WAITLIST or when specific fare classes are closed. Waitlisted passengers are cleared in priority order as cancellations occur.',
    CONSTRAINT pk_flight_inventory PRIMARY KEY(`flight_inventory_id`)
) COMMENT 'Core master entity representing the sellable seat inventory for a specific flight-date combination. Owns the authoritative record of total capacity, cabin breakdown, fare class bucket configuration, and overall availability status for each flight leg in the Amadeus AltĂ©a Inventory system. This is the primary inventory control record consumed by GDS, direct channels, and revenue management yield optimization.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`cabin_class` (
    `cabin_class_id` BIGINT COMMENT 'Unique surrogate identifier for the cabin class record within the airlines inventory system. Primary key for this reference master entity.',
    `part_master_id` BIGINT COMMENT 'Foreign key linking to procurement.part_master. Business justification: Cabin configurations require specific parts (seats, IFE units, galley equipment). Procurement must know which parts are compatible with each cabin class for refurbishment projects, spare parts plannin',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Each cabin class has distinct cost structures (service, catering, crew ratios). Airlines track cabin-level profitability by allocating costs to cabin class cost centers for yield management and produc',
    `applicable_flight_range` STRING COMMENT 'Flight range category for which this cabin class configuration is applicable: short_haul (under 3 hours), medium_haul (3â€“6 hours), long_haul (6â€“12 hours), ultra_long_haul (over 12 hours), or all. Drives route-specific product deployment and inventory segmentation.. Valid values are `short_haul|medium_haul|long_haul|ultra_long_haul|all`',
    `baggage_allowance_kg` DECIMAL(18,2) COMMENT 'Standard checked baggage allowance in kilograms included with the base fare for this cabin class. Drives ancillary revenue calculations, passenger service standards, and GDS fare display. Governed by IATA Resolution 302 weight concept.',
    `baggage_pieces_allowed` STRING COMMENT 'Number of checked baggage pieces included in the standard allowance for this cabin class under the piece concept. Applicable for routes governed by IATA piece concept (primarily transatlantic and transpacific). Complements baggage_allowance_kg for weight-concept routes.',
    `cabin_class_status` STRING COMMENT 'Current lifecycle status of the cabin class record. active indicates the cabin is currently offered and sellable; inactive indicates temporarily suspended; retired indicates permanently discontinued; pending indicates configured but not yet activated for sale.. Valid values are `active|inactive|retired|pending`',
    `cabin_code` STRING COMMENT 'Airline-internal alphanumeric code uniquely identifying the cabin class within the carriers Passenger Service System (PSS). Used in Amadeus AltĂ©a Inventory for cabin-level availability and inventory management. May differ from the IATA designator when the airline operates sub-cabin variants.. Valid values are `^[A-Z0-9]{2,6}$`',
    `cabin_name` STRING COMMENT 'Commercial marketing name of the cabin class as presented to passengers and travel agents (e.g., First Class, Business Class, Premium Economy, Economy). Used in passenger-facing communications, booking flows, and GDS displays.',
    `cabin_type` STRING COMMENT 'Standardized classification of the cabin into one of the four IATA-recognized commercial cabin tiers: first, business, premium_economy, or economy. Drives revenue management segmentation, yield optimization in Sabre AirVision, and inventory bucket hierarchy.. Valid values are `first|business|premium_economy|economy`',
    `carry_on_allowance_kg` DECIMAL(18,2) COMMENT 'Maximum weight in kilograms permitted for carry-on baggage in the cabin for this cabin class. Used in ground handling operations, security screening coordination with TSA/EASA, and passenger service standards.',
    `codeshare_sellable` BOOLEAN COMMENT 'Indicates whether this cabin class can be sold on codeshare flights operated by partner airlines. When true, inventory allocations for this cabin are made available to codeshare partners through interline agreements. Drives GDS availability display for codeshare itineraries.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this cabin class record was first created in the system. Supports data lineage, audit trail, and regulatory record-keeping requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `discontinuation_date` DATE COMMENT 'Date on which this cabin class definition is retired and no longer available for new bookings. Null for currently active cabin classes. Supports historical inventory analysis and regulatory record retention requirements.',
    `effective_date` DATE COMMENT 'Date from which this cabin class definition becomes commercially active and available for sale. Used for seasonal product changes, new aircraft type introductions, and cabin reconfiguration projects. Aligns with IATA Season scheduling conventions.',
    `fare_basis_prefix` STRING COMMENT 'Standard alphabetic prefix used in fare basis codes for this cabin class (e.g., Y for Economy, C for Business, F for First). Aligns fare construction with IATA fare basis code conventions and drives revenue management fare class bucket assignment in Sabre AirVision.. Valid values are `^[A-Z]{1,3}$`',
    `ffp_accrual_multiplier` DECIMAL(18,2) COMMENT 'Multiplier applied to base miles flown to calculate Frequent Flyer Program (FFP) miles or points accrued for travel in this cabin class. For example, a value of 2.0 means passengers earn double miles. Feeds Oracle Loyalty Cloud FFP accrual engine.',
    `gds_display_code` STRING COMMENT 'Code used to represent this cabin class in Global Distribution System (GDS) availability displays (e.g., Amadeus, Sabre, Travelport). May differ from the internal cabin_code for legacy GDS compatibility. Ensures correct cabin identification in travel agent booking workflows.. Valid values are `^[A-Z]{1,4}$`',
    `iata_cabin_designator` STRING COMMENT 'Single-letter IATA standard cabin designator code identifying the commercial cabin class (e.g., F = First, C = Business, W = Premium Economy, Y = Economy). Used as the industry-standard booking class grouping code across Global Distribution Systems (GDS) and interline agreements.. Valid values are `^[A-Z]{1}$`',
    `ife_type` STRING COMMENT 'Type of In-Flight Entertainment (IFE) system available in this cabin class: seatback_screen = personal seatback display, overhead_screen = shared overhead monitors, personal_device = bring-your-own-device streaming, none = no IFE. Used in product definition and passenger experience standards.. Valid values are `seatback_screen|overhead_screen|personal_device|none`',
    `is_lie_flat` BOOLEAN COMMENT 'Indicates whether the seats in this cabin class convert to a fully flat sleeping surface (180-degree recline). True for premium long-haul First and Business class products. Critical for product differentiation, revenue management premium pricing, and GDS display.',
    `lounge_access_entitlement` STRING COMMENT 'Level of airport lounge access included with this cabin class: none = no lounge access, home_carrier = access to the airlines own lounges only, partner = access to partner airline lounges, all_alliance = full alliance lounge network access. Drives ground handling instructions and passenger service delivery.. Valid values are `none|home_carrier|partner|all_alliance`',
    `max_overbooking_pct` DECIMAL(18,2) COMMENT 'Maximum percentage above physical seat capacity that bookings may be accepted for this cabin class under the airlines overbooking policy. For example, 10.00 means up to 110% of seats may be sold. Null when overbooking_allowed is false. Governed by DOT regulations.',
    `meal_service_type` STRING COMMENT 'Standard meal service type provided in this cabin class: full_meal = multi-course meal service, light_meal = single-course meal, snack = snack and beverage only, buy_on_board = no complimentary meal, none = no food service. Drives catering uplift planning and galley configuration.. Valid values are `full_meal|light_meal|snack|buy_on_board|none`',
    `overbooking_allowed` BOOLEAN COMMENT 'Indicates whether overbooking is permitted for this cabin class. When true, the inventory system may accept bookings beyond physical seat capacity based on no-show forecasting models. Governed by DOT overbooking regulations and airline revenue management policy.',
    `power_outlet_type` STRING COMMENT 'Type of in-seat power outlet available in this cabin class: ac_110v, ac_220v, usb_a, usb_c, or none. Used in product specification, passenger communication, and aircraft configuration management in AMOS.. Valid values are `ac_110v|ac_220v|usb_a|usb_c|none`',
    `priority_boarding` BOOLEAN COMMENT 'Indicates whether passengers in this cabin class receive priority boarding privileges ahead of general boarding groups. Drives boarding sequence configuration in SITA Airport Management Platform and ground handling SOPs.',
    `priority_check_in` BOOLEAN COMMENT 'Indicates whether passengers in this cabin class are entitled to dedicated priority check-in counters or lanes. Drives airport operations configuration in SITA Airport Management Platform and ground handling service level agreements.',
    `revenue_class_hierarchy` STRING COMMENT 'Numeric rank defining the commercial hierarchy of this cabin class relative to others (1 = highest/First, 4 = lowest/Economy). Used by Sabre AirVision Revenue Management for yield optimization, upgrade logic, and inventory nesting rules. Lower number = higher revenue class.',
    `seat_configuration_code` STRING COMMENT 'Standard seat layout configuration code for this cabin class expressed as a row-abreast pattern (e.g., 2-2-2 for Business, 3-3-3 for Economy). Reflects the physical seat arrangement across the aircraft cross-section. Sourced from aircraft type configuration in AMOS.. Valid values are `^[0-9]{1,2}-[0-9]{1,2}(-[0-9]{1,2})?$`',
    `seat_pitch_inches` DECIMAL(18,2) COMMENT 'Distance in inches between a point on one seat and the same point on the seat directly in front, representing legroom standard for this cabin class. Key product differentiation metric used in marketing, regulatory DOT reporting, and passenger experience benchmarking.',
    `seat_recline_inches` DECIMAL(18,2) COMMENT 'Maximum recline distance in inches for seats in this cabin class. Distinguishes flat-bed (Business/First) from recliner (Premium Economy) and standard recline (Economy) product tiers. Used in product definition and passenger experience standards.',
    `seat_width_inches` DECIMAL(18,2) COMMENT 'Width of the seat in inches for this cabin class, measured at the widest point of the seat cushion. Used in product specification, passenger comfort benchmarking, and marketing collateral.',
    `service_level_description` STRING COMMENT 'Narrative description of the service standards, amenities, and passenger experience associated with this cabin class. Includes details such as meal service type, lounge access entitlement, priority boarding, and onboard entertainment offerings. Used for product definition and customer communication.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this cabin class definition originates (e.g., ALTEA_INV for Amadeus AltĂ©a Inventory, SABRE_RM for Sabre AirVision). Supports data lineage tracking in the Databricks Silver Layer lakehouse.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this cabin class record. Used for change tracking, data synchronization with downstream systems (GDS, Revenue Management), and audit compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `upgrade_eligible` BOOLEAN COMMENT 'Indicates whether passengers booked in this cabin class are eligible to receive complimentary or paid upgrades to a higher cabin class. Drives upgrade logic in Amadeus AltĂ©a Inventory and Oracle Loyalty Cloud FFP upgrade award processing.',
    `upgrade_target_cabin_code` STRING COMMENT 'Cabin code of the next higher cabin class to which passengers in this cabin may be upgraded. Null for the highest cabin class (First). Used in automated upgrade processing and FFP award redemption workflows.. Valid values are `^[A-Z0-9]{2,6}$`',
    `wifi_available` BOOLEAN COMMENT 'Indicates whether in-flight Wi-Fi connectivity is available in this cabin class. Drives ancillary service offerings, passenger communication, and product marketing. Complements IFE type for digital connectivity product definition.',
    CONSTRAINT pk_cabin_class PRIMARY KEY(`cabin_class_id`)
) COMMENT 'Reference master defining the physical and commercial cabin classes operated by the airline (e.g., First, Business, Premium Economy, Economy). Captures IATA cabin designator codes, seat configuration standards, service level definitions, and applicable aircraft type associations. Used as the classification backbone for inventory segmentation and revenue management.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`fare_class_bucket` (
    `fare_class_bucket_id` BIGINT COMMENT 'Unique surrogate identifier for the fare class bucket record in the Silver layer. Primary key for this entity.',
    `cabin_class_id` BIGINT COMMENT 'Foreign key linking to inventory.cabin_class. Business justification: fare_class_bucket defines RBD buckets within a cabin class. cabin_class is the reference master for cabin definitions. This FK establishes the cabin hierarchy for fare class buckets. cabin_code is red',
    `catering_order_id` BIGINT COMMENT 'Foreign key linking to procurement.catering_order. Business justification: Fare class bookings drive catering order meal counts by service class. Revenue management bucket changes trigger catering order adjustments. Daily operational link between inventory yield management a',
    `inventory_leg_id` BIGINT COMMENT 'Reference to the flight inventory leg record to which this fare class bucket belongs. Links the bucket to a specific flight-date-leg combination managed in AltĂ©a Inventory.',
    `promotional_fare_id` BIGINT COMMENT 'Foreign key linking to marketing.promotional_fare. Business justification: Promotional fares must be mapped to specific RBD buckets for inventory control. Revenue management systems authorize promotional inventory at the bucket level. Critical for integrating marketing promo',
    `advance_purchase_days` STRING COMMENT 'Minimum number of days before departure that a ticket must be purchased to qualify for fares in this booking class (e.g., 7, 14, 21). A value of 0 indicates no advance purchase requirement. Governs ticketing time limit enforcement in AltĂ©a.',
    `allotment_type` STRING COMMENT 'Classification of the inventory allocation type for this bucket: own (operating carrier direct sale), codeshare (partner airline marketing), interline (interline ticketing agreement), group (group booking block), charter (charter operator block), blocked (operationally blocked seats). Drives revenue accounting and settlement routing.. Valid values are `own|codeshare|interline|group|charter|blocked`',
    `authorized_units` STRING COMMENT 'Authorized capacity (AU) â€” the maximum number of seats the revenue management system has authorized for sale in this booking class bucket for the flight leg. Set by Sabre AirVision yield optimization and loaded into AltĂ©a Inventory. Core inventory control parameter.',
    `availability_code` STRING COMMENT 'IATA standard availability status code transmitted to GDS systems (e.g., A = available, L = waitlist, R = request, C = closed). Distinct from bucket_status in that this is the externally-broadcast GDS code per IATA PADIS standards, while bucket_status is the internal operational state.. Valid values are `^[A-Z0-9]{1,2}$`',
    `availability_snapshot_timestamp` TIMESTAMP COMMENT 'Timestamp at which the current availability figures (seats_available, current_bookings, load_factor_pct) were captured from AltĂ©a Inventory. Critical for GDS cache freshness validation and real-time availability SLA monitoring.',
    `booking_limit` STRING COMMENT 'Booking limit (BL) â€” the maximum cumulative number of bookings permitted across this bucket and all lower-yield buckets nested beneath it. Enforced in real time by AltĂ©a Inventory to prevent overselling beyond the authorized level.',
    `bucket_rank` STRING COMMENT 'Ordinal position of this RBD bucket within its cabin hierarchy, from highest-yield (rank 1) to lowest-yield. Used by Sabre AirVision and AltĂ©a Inventory to determine availability cascade â€” a lower-ranked (higher-yield) bucket must be open before a higher-ranked (lower-yield) bucket can sell.',
    `bucket_status` STRING COMMENT 'Current availability status of the fare class bucket as broadcast to GDS and direct channels: open (seats available for sale), closed (no availability â€” bucket is shut by RM or capacity), waitlist (no confirmed seats but waitlist accepted), request_only (requires manual approval), suspended (temporarily removed from sale by operations).. Valid values are `open|closed|waitlist|request_only|suspended`',
    `change_fee_amount` DECIMAL(18,2) COMMENT 'Monetary penalty charged to the passenger for a voluntary itinerary change on a ticket issued under this booking class, expressed in the filing currency. A value of 0.00 indicates no change fee. Commercially sensitive pricing parameter.',
    `change_fee_currency` STRING COMMENT 'ISO 4217 three-letter currency code in which the change fee amount is denominated (e.g., USD, EUR, GBP). Required for multi-currency fare filing and BSP/ARC settlement.. Valid values are `^[A-Z]{3}$`',
    `codeshare_indicator` BOOLEAN COMMENT 'Indicates whether this fare class bucket is allocated for codeshare inventory (True) â€” i.e., seats sold under a partner airlines flight number â€” or is for the operating carriers own inventory (False). Governs interline proration and codeshare revenue accounting.',
    `codeshare_partner_code` STRING COMMENT 'IATA two-letter airline designator of the codeshare marketing partner for whom this bucket allocation is reserved (e.g., LH, BA, AA). Null for own-carrier inventory. Used for interline settlement and codeshare capacity reporting.. Valid values are `^[A-Z0-9]{2}$`',
    `current_bookings` STRING COMMENT 'Number of confirmed bookings currently held against this fare class bucket. Updated in near-real-time from AltĂ©a Inventory as PNRs are created, modified, or cancelled. Used to compute remaining availability.',
    `effective_from` DATE COMMENT 'Calendar date from which this fare class bucket configuration becomes active for sale. Used for seasonal inventory planning and schedule-period bucket management in AltĂ©a Inventory.',
    `effective_until` DATE COMMENT 'Calendar date after which this fare class bucket configuration is no longer active. Null indicates the bucket remains open-ended until explicitly closed. Supports seasonal and schedule-period inventory lifecycle management.',
    `fare_basis_code` STRING COMMENT 'IATA fare basis code associated with the primary fare filed under this booking class bucket (e.g., YOWUS, BAPUS21). Links the inventory bucket to the fare tariff filed with ATPCO. Used for ticketing, interline proration, and BSP/ARC settlement.. Valid values are `^[A-Z0-9]{1,10}$`',
    `fare_family_code` STRING COMMENT 'Branded fare family or product bundle code associated with this booking class (e.g., BASIC, STANDARD, FLEX, BUSINESS_PLUS). Aligns the RBD bucket with the airlines branded fare product hierarchy for ancillary bundling and NDC offer construction.',
    `group_block_seats` STRING COMMENT 'Number of seats within this bucket reserved as a group block allocation. A value of 0 indicates no group block. Group blocks are managed separately from individual seat availability and are subject to group contract terms.',
    `is_changeable` BOOLEAN COMMENT 'Indicates whether the itinerary booked under this fare class may be voluntarily changed (True) or is a fixed non-changeable ticket (False). Relevant for IROP handling, voluntary rebooking, and ancillary change-fee revenue.',
    `is_refundable` BOOLEAN COMMENT 'Indicates whether tickets issued under this booking class are eligible for a full or partial refund (True) or are non-refundable (False). Drives customer service handling, involuntary rerouting compensation, and DOT consumer protection compliance.',
    `last_rm_update_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent authorized unit or booking limit update pushed from Sabre AirVision to AltĂ©a Inventory. Enables audit of RM optimization cycle frequency and latency monitoring between the two systems.',
    `load_factor_pct` DECIMAL(18,2) COMMENT 'Current load factor for this fare class bucket expressed as a percentage (current_bookings / authorized_units Ă— 100). Stored as a snapshot field for real-time RM monitoring and GDS availability optimization. Aligns with IATA load factor (percentage of seats filled) definition.',
    `max_stay_days` STRING COMMENT 'Maximum number of days the passenger may remain at the destination before return travel must commence for fares in this booking class. A null value indicates no maximum stay restriction. Standard fare restriction filed with ATPCO.',
    `min_stay_days` STRING COMMENT 'Minimum number of days the passenger must remain at the destination before return travel is permitted for fares in this booking class. A value of 0 indicates no minimum stay restriction. Standard fare restriction filed with ATPCO.',
    `overbooking_factor` DECIMAL(18,2) COMMENT 'Fractional multiplier applied to physical seat capacity to derive the authorized overbooking level for this bucket (e.g., 1.0500 = 5% overbooking). Set by revenue management based on historical no-show and cancellation rates. Commercially sensitive â€” drives denied boarding exposure. Governed by DOT 14 CFR Part 250.',
    `protection_level` STRING COMMENT 'Number of seats protected (reserved) for higher-yield demand in this bucket, as computed by the EMSR (Expected Marginal Seat Revenue) optimization in Sabre AirVision. Prevents lower-yield bookings from displacing higher-yield passengers. Core RM optimization output.',
    `rbd_code` STRING COMMENT 'Single uppercase IATA letter identifying the booking class (e.g., Y, B, M, Q, V, H, K, L, S, N, O, G). The RBD is the atomic unit of inventory control in AltĂ©a Inventory and the direct input to Sabre AirVision yield optimization. Governed by IATA Resolution 728.. Valid values are `^[A-Z]$`',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this fare class bucket record was first created in the Silver layer data product. Supports data lineage, audit trail, and SLA compliance tracking per enterprise data governance standards.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this fare class bucket record in the Silver layer. Used for incremental load detection, change data capture, and audit compliance.',
    `seats_available` STRING COMMENT 'Current number of seats available for sale in this booking class bucket at the time of the last inventory snapshot. Derived operationally as booking_limit minus current_bookings, but stored as a first-class field for GDS availability response performance. Consumed by GDS channels and direct booking engines.',
    `sell_up_target_rbd` STRING COMMENT 'The preferred higher-yield RBD code to which Sabre AirVision should attempt to sell up when this bucket is closed or constrained. Commercially sensitive RM strategy parameter used in availability cascade logic.. Valid values are `^[A-Z]$`',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record that originated or last updated this fare class bucket record: ALTEA (Amadeus AltĂ©a Inventory), SABRE_AV (Sabre AirVision Revenue Management), MANUAL (manually entered override), MIGRATION (data migration load). Supports data lineage and audit in the Silver layer.. Valid values are `ALTEA|SABRE_AV|MANUAL|MIGRATION`',
    `waitlist_count` STRING COMMENT 'Current number of waitlisted booking requests queued against this fare class bucket. When seats become available (e.g., cancellations), AltĂ©a Inventory automatically clears waitlisted PNRs in queue order.',
    `yield_class` STRING COMMENT 'Revenue management yield classification assigned to this bucket by Sabre AirVision, grouping RBDs into broad yield tiers for reporting and optimization. Commercially sensitive as it reveals pricing strategy segmentation.. Valid values are `high|medium|low|ultra_low`',
    CONSTRAINT pk_fare_class_bucket PRIMARY KEY(`fare_class_bucket_id`)
) COMMENT 'Master entity defining individual booking class (RBD â€” Reservation Booking Designator) buckets within a cabin for a flight inventory record. Captures the single-letter IATA booking class code (e.g., Y, B, M, Q, V), the hierarchical nesting within the cabin, authorized capacity (AU), booking limit (BL), overbooking factor, and current availability status. The atomic unit of inventory control in AltĂ©a Inventory and the direct input to Sabre AirVision yield optimization.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`seat_availability` (
    `seat_availability_id` BIGINT COMMENT 'Unique surrogate identifier for each seat availability snapshot record in the inventory system. Primary key for this data product.',
    `catering_order_id` BIGINT COMMENT 'Foreign key linking to procurement.catering_order. Business justification: Real-time seat availability snapshots determine final catering order quantities. Catering cutoff decisions use latest availability data to minimize waste and ensure adequate provisioning. Critical for',
    `fare_class_bucket_id` BIGINT COMMENT 'Foreign key linking to inventory.fare_class_bucket. Business justification: seat_availability tracks availability for a specific fare class bucket (RBD). fare_class_bucket is the master entity defining RBD buckets. This FK links transactional availability records to the bucke',
    `flight_inventory_id` BIGINT COMMENT 'Foreign key linking to inventory.flight_inventory. Business justification: seat_availability records are real-time availability snapshots for a specific flight-date combination. flight_inventory is the master entity for that flight-date. This FK establishes the natural paren',
    `flight_leg_id` BIGINT COMMENT 'Reference to the operating flight record for which seat availability is being tracked. Links to the flight master entity.',
    `availability_status` STRING COMMENT 'Current booking status of the fare class bucket as broadcast to distribution channels. Open = seats available for sale; Closed = bucket closed by revenue management; Waitlist = waitlist accepted; Request = booking requires airline confirmation; Sold Out = no seats remain. Core inventory control signal consumed by GDS, NDC, and direct channels.. Valid values are `Open|Closed|Waitlist|Request|Sold Out`',
    `availability_version` STRING COMMENT 'Monotonically increasing version counter for this flight-date-fare-class availability record. Enables ordering of multiple snapshots for the same key and supports optimistic concurrency control in the Silver layer.',
    `booking_class_availability_map` STRING COMMENT 'Availability status string (AVS) representing the full cabin availability across all booking classes at the time of snapshot, as broadcast in GDS availability responses (e.g., Y9B9M9Q4V0). Enables reconstruction of the complete availability display seen by travel agents.',
    `broadcast_timestamp` TIMESTAMP COMMENT 'Date and time when this availability update was broadcast to GDS and distribution channels. Distinct from snapshot_timestamp (capture time) and last_updated_timestamp (system update time). Used for GDS broadcast latency measurement and SLA verification.',
    `cabin_class` STRING COMMENT 'Physical cabin designation to which the fare class bucket belongs (e.g., First, Business, Premium Economy, Economy). Used for cabin-level load factor reporting and capacity management.. Valid values are `First|Business|Premium Economy|Economy`',
    `codeshare_allotment` STRING COMMENT 'Number of seats allocated to the codeshare marketing partner within this fare class bucket. Null when codeshare_indicator is false. Used to track partner inventory consumption against agreed allotment caps.',
    `codeshare_indicator` BOOLEAN COMMENT 'Flag indicating whether this availability record pertains to a codeshare flight operation where the marketing carrier differs from the operating carrier. When true, inventory is managed under a codeshare allocation agreement.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this availability snapshot record was first created in the data platform. Audit trail field for Silver layer data lineage and regulatory compliance.',
    `days_to_departure` STRING COMMENT 'Number of calendar days between the snapshot_timestamp date and the flight_date. Critical dimension for revenue management booking curve analysis and yield optimization model training.',
    `distribution_channel` STRING COMMENT 'Channel context for which this availability snapshot was generated or broadcast. GDS = Global Distribution System (Amadeus, Sabre, Travelport); NDC = IATA New Distribution Capability; Direct = airline.com or mobile app; API = B2B direct connect; Interline = partner carrier ticketing; Codeshare = shared flight operation partner.. Valid values are `GDS|NDC|Direct|API|Interline|Codeshare`',
    `forecast_demand` STRING COMMENT 'Revenue management systems demand forecast for this fare class bucket at the time of the snapshot, expressed as expected number of bookings. Captured alongside actual availability for model accuracy tracking and yield optimization.',
    `gds_provider_code` STRING COMMENT 'IATA-assigned GDS provider code identifying the specific GDS to which this availability was broadcast: 1A = Amadeus, 1S = Sabre, 1G = Galileo (Travelport), 1P = Worldspan (Travelport). Null when distribution_channel is not GDS.. Valid values are `1A|1S|1G|1P`',
    `inventory_control_mode` STRING COMMENT 'Method by which inventory is controlled for this availability record: Leg = physical leg-based control; Segment = segment-level control; OD = Origin-Destination (virtual nesting / O&D control). Determines how Amadeus AltĂ©a manages seat allocation across connecting itineraries.. Valid values are `Leg|Segment|OD`',
    `is_current_snapshot` BOOLEAN COMMENT 'Flag indicating whether this record represents the most recent (current) availability snapshot for the flight-date-fare-class combination. Enables efficient point-in-time queries without full history scan. Set to false when superseded by a newer snapshot.',
    `is_interline_eligible` BOOLEAN COMMENT 'Flag indicating whether this fare class bucket is open for interline ticketing by partner carriers under bilateral interline agreements. Governs availability visibility in interline booking flows.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this availability record was last modified in the source inventory system (Amadeus AltĂ©a). Used for GDS broadcast verification, change detection, and Silver layer incremental processing.',
    `load_factor_pct` DECIMAL(18,2) COMMENT 'Percentage of authorized seats sold at the time of this snapshot, calculated as (seats_sold / seats_authorized) Ă— 100. Captured at snapshot time for historical revenue management model training and GDS broadcast audit. Aligns with IATA load factor (percentage of seats filled) definition.',
    `marketing_carrier_code` STRING COMMENT 'Two-character IATA airline designator of the carrier under whose flight number the seat is sold to passengers. On non-codeshare flights this equals the operating carrier code.. Valid values are `^[A-Z0-9]{2}$`',
    `nesting_level` STRING COMMENT 'Hierarchical nesting position of this fare class bucket within the cabins virtual nesting structure used by the revenue management system. Lower values indicate higher-yield buckets. Governs availability inheritance between fare classes.',
    `operating_carrier_code` STRING COMMENT 'Two-character IATA airline designator of the carrier physically operating the flight. Differs from the marketing carrier on codeshare flights. Required for interline and codeshare inventory allocation tracking.. Valid values are `^[A-Z0-9]{2}$`',
    `overbooking_factor` DECIMAL(18,2) COMMENT 'Authorized overbooking multiplier applied to physical seat capacity for this fare class bucket, expressed as a percentage above 100 (e.g., 105.00 = 5% overbooking). Set by revenue management to compensate for expected no-shows and cancellations.',
    `physical_capacity` STRING COMMENT 'Total number of physical seats configured in the cabin for this flight-date, before overbooking authorization. Provides the denominator for cabin-level load factor calculations and capacity planning.',
    `protection_level` STRING COMMENT 'Number of seats protected (reserved) for higher-yield fare classes above this bucket in the nesting hierarchy, as set by the revenue management optimizer. Core EMSR (Expected Marginal Seat Revenue) output used in AltĂ©a and Sabre inventory control.',
    `rm_decision_code` STRING COMMENT 'Code identifying the revenue management optimization decision or rule that triggered the current availability status or booking limit for this fare class bucket (e.g., FCST_CLOSE, MANUAL_OVERRIDE, AUTO_OPEN). Supports RM model audit and performance attribution.',
    `seats_authorized` STRING COMMENT 'Maximum number of bookings authorized for this fare class bucket as set by the revenue management system. Represents the booking limit or allotment cap controlling inventory exposure for this RBD.',
    `seats_available` STRING COMMENT 'Number of seats currently available for sale in this fare class bucket at the time of the snapshot. A value of zero with status Open may indicate overbooking authorization. Negative values indicate oversold position.',
    `seats_held` STRING COMMENT 'Number of seats temporarily held under option, group block, or tour operator allotment that are not yet confirmed bookings but reduce net availability. Distinct from seats_sold as these may be released.',
    `seats_sold` STRING COMMENT 'Number of confirmed bookings (including checked-in passengers) held against this fare class bucket at the time of the snapshot. Used to compute load factor and remaining availability.',
    `snapshot_timestamp` TIMESTAMP COMMENT 'Exact date and time (ISO 8601 with timezone offset) at which this availability record was captured or broadcast. The principal business event timestamp for this EVENT_LOG record. Used for GDS broadcast verification and revenue management time-series analysis.',
    `snapshot_trigger` STRING COMMENT 'Business event or system action that caused this availability snapshot to be generated and broadcast. Enables audit of why availability changed at a given point in time. [ENUM-REF-CANDIDATE: Booking|Cancellation|Schedule Change|RM Override|GDS Poll|NDC Request|Overbooking Adjustment|Batch Interval â€” promote to reference product]',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record that originated this availability record: ALTEA = Amadeus AltĂ©a Inventory (PSS); SABRE = Sabre AirVision Revenue Management; NETLINE = Lufthansa Systems NetLine/Ops; MANUAL = manually entered override.. Valid values are `ALTEA|SABRE|NETLINE|MANUAL`',
    `waitlist_count` STRING COMMENT 'Number of passengers currently on the waitlist for this fare class bucket at the time of the snapshot. Relevant when availability_status is Waitlist. Used to assess demand pressure and inform overbooking decisions.',
    CONSTRAINT pk_seat_availability PRIMARY KEY(`seat_availability_id`)
) COMMENT 'Real-time and historical transactional record of seat availability by fare class bucket for a flight-date, as broadcast to distribution channels and captured at scheduled intervals for audit and analytics. Captures available seat count, status code (Open/Closed/Waitlist), last update timestamp, channel context (GDS, NDC, direct), snapshot trigger reason, and load factor at capture time. Serves as both the live availability signal consumed by Amadeus, Sabre, and Travelport systems and the historical availability audit trail for revenue management model training and GDS broadcast verification.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`overbooking_control` (
    `overbooking_control_id` BIGINT COMMENT 'Unique surrogate identifier for the overbooking control record. Primary key for this entity.',
    `cabin_class_id` BIGINT COMMENT 'Foreign key linking to inventory.cabin_class. Business justification: overbooking_control stores overbooking authorization parameters for a specific cabin class. cabin_class is the reference master for cabin definitions. This FK links control parameters to the cabin mas',
    `catering_order_id` BIGINT COMMENT 'Foreign key linking to procurement.catering_order. Business justification: Overbooking authorization changes affect expected passenger counts and thus catering requirements. Catering supervisors adjust meal orders based on overbooking limits to balance service levels and was',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: Denied boarding compensation (voluntary and involuntary) is a direct cost tracked by cost center for financial reporting and DOT/regulatory compliance. Airlines monitor IDB costs against overbooking r',
    `employee_id` BIGINT COMMENT 'Reference to the revenue management analyst who applied the manual override. Populated only when rm_system_override_flag is True. Supports audit trail and accountability requirements.',
    `flight_inventory_id` BIGINT COMMENT 'Reference to the flight inventory record (specific flight departure date and flight number combination) to which this overbooking control applies. Links to the sellable inventory unit in AltĂ©a Inventory.',
    `regulatory_requirement_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_requirement. Business justification: Overbooking limits are constrained by passenger rights regulations (EU261, DOT Part 250). Overbooking control records must reference the regulatory requirement defining maximum oversale thresholds and',
    `authorized_overbooking_pct` DECIMAL(18,2) COMMENT 'The approved percentage above physical cabin seat capacity that the revenue management system is authorized to sell. For example, a value of 10.00 means up to 10% more seats than physically available may be booked. Derived from historical no-show rates and spoilage risk models in Sabre AirVision Revenue Management.',
    `availability_snapshot_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent real-time availability snapshot published to GDS and direct booking channels by AltĂ©a Inventory. Indicates the currency of the current_booking_count and booking_limit values.',
    `avg_fare_value_usd` DECIMAL(18,2) COMMENT 'The average fare value in USD for bookings in this cabin on this flight, used as an input to the overbooking revenue optimization model. Enables the model to weigh the revenue benefit of additional bookings against the cost of denied boarding compensation.',
    `booking_limit` STRING COMMENT 'The computed maximum number of bookings permitted for this cabin on this flight, equal to physical seat capacity plus authorized oversale seats. This is the operative value consumed by AltĂ©a Inventory and GDS availability responses to control seat sales.',
    `cancellation_rate_input` DECIMAL(18,2) COMMENT 'Historical cancellation rate (expressed as a decimal proportion) for this route, cabin, and season used as an actuarial input alongside the no-show rate in the overbooking model. Distinct from no-show rate as it captures pre-departure cancellations.',
    `codeshare_inventory_flag` BOOLEAN COMMENT 'Indicates whether this overbooking control applies to a codeshare inventory allocation rather than the operating carriers own inventory. Codeshare overbooking controls may differ from mainline controls due to interline agreements and partner airline seat block commitments.',
    `control_status` STRING COMMENT 'Current lifecycle status of this overbooking control record. Active indicates the parameters are live and being applied by AltĂ©a Inventory booking limit calculations. Suspended means overbooking is temporarily halted for this cabin. Overridden indicates a manual revenue management analyst override is in effect.. Valid values are `active|suspended|pending_review|overridden|expired`',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this overbooking control record was first created in the system. Supports audit trail and data lineage requirements.',
    `current_booking_count` STRING COMMENT 'The real-time count of confirmed bookings (PNRs) held against this cabin at the time of the last availability snapshot. Used to compute remaining availability and monitor oversale exposure.',
    `day_of_week_pattern` STRING COMMENT 'Bitmask or string pattern (e.g., 1234567 where each digit represents Monâ€“Sun) indicating which days of the week this overbooking control applies to. Allows differentiated overbooking levels for weekday versus weekend departures.',
    `denied_boarding_risk_threshold` DECIMAL(18,2) COMMENT 'The maximum acceptable probability (expressed as a decimal, e.g., 0.0200 = 2%) that at least one passenger will be involuntarily denied boarding due to oversale. Balances revenue optimization against regulatory denied boarding compensation exposure under DOT 14 CFR Part 250 and IATA Resolution 830d.',
    `departure_date` DATE COMMENT 'The scheduled departure date of the flight to which this overbooking control record applies. Combined with the flight inventory reference, uniquely identifies the specific flight departure instance.',
    `effective_from` DATE COMMENT 'The date from which this overbooking control record becomes operative. Supports scheduling of future overbooking parameter changes in advance of the departure date.',
    `effective_until` DATE COMMENT 'The date after which this overbooking control record is no longer operative. Null indicates the record remains active indefinitely until superseded. Supports time-bounded overbooking strategies.',
    `go_show_rate_input` DECIMAL(18,2) COMMENT 'Historical rate of passengers who arrive at the gate without a prior reservation (go-shows) for this route and cabin, expressed as a decimal proportion. Used in the overbooking model to account for demand that materialises at departure.',
    `group_booking_seats_reserved` STRING COMMENT 'Number of seats within the cabin that are reserved for confirmed group bookings and excluded from the overbooking calculation. Group bookings typically have lower no-show rates and are treated separately in the overbooking model.',
    `historical_no_show_rate` DECIMAL(18,2) COMMENT 'The input no-show rate (expressed as a decimal proportion, e.g., 0.0850 = 8.50%) derived from historical passenger behaviour for this route, cabin, and season. Used as the primary actuarial input to the overbooking authorization model in Sabre AirVision.',
    `idb_compensation_exposure_usd` DECIMAL(18,2) COMMENT 'Estimated maximum financial exposure in USD for involuntary denied boarding (IDB) compensation if all oversold seats result in IDB events. Calculated based on max_oversale_seats and applicable DOT/IATA compensation rates. Used in revenue management risk assessment.',
    `last_reviewed_timestamp` TIMESTAMP COMMENT 'The date and time when a revenue management analyst last reviewed and confirmed or adjusted this overbooking control record. Supports governance workflows requiring periodic review of overbooking authorizations.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this overbooking control record was most recently modified. Tracks parameter changes by revenue management analysts or automated system recalculations.',
    `load_factor_forecast` DECIMAL(18,2) COMMENT 'The forecasted load factor (proportion of physical seats expected to be occupied at departure, expressed as a decimal e.g., 0.9200 = 92%) for this cabin on this flight. Input from Sabre AirVision demand forecasting, used to calibrate the overbooking level.',
    `max_oversale_seats` STRING COMMENT 'The absolute maximum number of seats above physical cabin capacity that may be sold, regardless of the authorized overbooking percentage. Acts as a hard cap to limit denied boarding exposure. Set by revenue management analysts in AltĂ©a Inventory.',
    `next_review_date` DATE COMMENT 'The scheduled date by which this overbooking control record must be reviewed by a revenue management analyst. Drives workflow queuing in Sabre AirVision to ensure timely recalibration before departure.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes or context related to this overbooking control record, such as special event considerations, IROP recovery instructions, or coordination notes with ground handling teams.',
    `overbooking_model_version` STRING COMMENT 'Version identifier of the statistical overbooking model used to compute the authorized overbooking percentage for this record. Enables reproducibility, model governance, and comparison of model performance across versions in Sabre AirVision.',
    `override_reason` STRING COMMENT 'Free-text justification provided by the revenue management analyst when rm_system_override_flag is True. Documents the business rationale for departing from the system-recommended overbooking level (e.g., special event, group booking, IROP recovery).',
    `physical_seat_capacity` STRING COMMENT 'The actual number of physical seats available in the cabin for this flight departure, as configured in the aircraft fleet assignment. This is the baseline against which the overbooking percentage is applied.',
    `regulatory_market_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code or regulatory jurisdiction code (e.g., USA, EU) identifying the regulatory regime governing denied boarding compensation obligations for this flight. Determines applicable DOT, EASA EC 261/2004, or national civil aviation authority rules.',
    `rm_system_override_flag` BOOLEAN COMMENT 'Indicates whether a revenue management analyst has manually overridden the system-calculated overbooking parameters. When True, the authorized_overbooking_pct and max_oversale_seats reflect analyst-entered values rather than the automated Sabre AirVision model output.',
    `season_code` STRING COMMENT 'IATA scheduling season code (e.g., S25 for Summer 2025, W24 for Winter 2024) during which this overbooking control is applicable. Overbooking parameters are typically calibrated per season based on seasonal demand and no-show patterns.',
    `source_system_code` STRING COMMENT 'Identifies the originating system that created or last updated this overbooking control record. ALTEA = Amadeus AltĂ©a Inventory automated calculation, SABRE_AV = Sabre AirVision Revenue Management model output, MANUAL = direct analyst entry.. Valid values are `ALTEA|SABRE_AV|MANUAL`',
    `spoilage_risk_threshold` DECIMAL(18,2) COMMENT 'The maximum acceptable probability (expressed as a decimal, e.g., 0.0500 = 5%) that the flight departs with empty seats due to under-booking. Revenue management uses this threshold to calibrate the overbooking level against the risk of seat spoilage versus denied boarding.',
    `upgrade_buffer_seats` STRING COMMENT 'Number of seats held back from the overbooking pool to accommodate anticipated operational upgrades (e.g., elite frequent flyer upgrades, compensation upgrades). Reduces the effective booking limit to preserve upgrade capacity.',
    `voluntary_denied_boarding_target` STRING COMMENT 'The target number of passengers expected to accept voluntary denied boarding (VDB) compensation offers at the gate in the event of an oversale. Used in the overbooking model to offset the involuntary denied boarding risk.',
    CONSTRAINT pk_overbooking_control PRIMARY KEY(`overbooking_control_id`)
) COMMENT 'Master entity storing the overbooking authorization parameters for a flight inventory record by cabin class. Captures the authorized overbooking percentage, maximum oversale seats, historical no-show rate inputs, spoilage risk threshold, and the revenue management system override flag. Directly managed by revenue management analysts and consumed by AltĂ©a Inventory to set booking limits above physical capacity.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`codeshare_allocation` (
    `codeshare_allocation_id` BIGINT COMMENT 'Unique surrogate identifier for the codeshare or interline inventory allocation record within the Amadeus AltĂ©a Inventory system. Primary key for this entity.',
    `bilateral_asa_id` BIGINT COMMENT 'Reference to the governing bilateral codeshare or interline agreement between the operating carrier and the marketing carrier that authorises this allocation.',
    `cabin_class_id` BIGINT COMMENT 'Foreign key linking to inventory.cabin_class. Business justification: codeshare_allocation defines seat allocations granted to codeshare partners for a specific cabin class. cabin_class is the reference master for cabin definitions. This FK links allocation records to t',
    `flight_inventory_id` BIGINT COMMENT 'Reference to the specific flight-date inventory record in the host carriers AltĂ©a Inventory for which this codeshare allocation is ring-fenced.',
    `carrier_id` BIGINT COMMENT 'Reference to the airline that physically operates the flight on which this inventory allocation is granted. The operating carrier owns the aircraft and crew.',
    `org_unit_id` BIGINT COMMENT 'Foreign key linking to workforce.org_unit. Business justification: Operating carriers in codeshare agreements are airline organizational units (divisions/subsidiaries). Essential for codeshare revenue allocation, bilateral agreement compliance tracking, and operation',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Operating carrier in codeshare is a vendor for settlement purposes. Prorate agreements, revenue sharing, and interline billing require vendor master linkage. Finance uses this for accounts payable/rec',
    `allocation_status` STRING COMMENT 'Current lifecycle state of the codeshare allocation record within AltĂ©a Inventory. active means the allocation is live and available for booking; suspended means temporarily halted; cancelled means permanently withdrawn; pending means awaiting activation; expired means the flight date has passed.. Valid values are `active|suspended|cancelled|pending|expired`',
    `allocation_type` STRING COMMENT 'Defines the inventory control mechanism governing this codeshare allocation. block_space means a fixed seat block is ring-fenced for the marketing carrier regardless of overall availability; free_flow means the marketing carrier draws from the operating carriers shared availability pool without a hard block; hybrid combines a guaranteed minimum block with free-flow access above it.. Valid values are `block_space|free_flow|hybrid`',
    `altea_allocation_reference` STRING COMMENT 'Native allocation reference identifier assigned by the Amadeus AltĂ©a Inventory system for this codeshare block. Used for reconciliation and traceability back to the operational PSS source record.',
    `authorized_seat_count` STRING COMMENT 'Maximum number of seats the marketing carrier is authorised to sell on this flight-date and cabin under this allocation. For block-space agreements this is the contracted block size; for free-flow it represents the cap agreed in the bilateral.',
    `availability_snapshot_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent real-time availability snapshot captured from AltĂ©a Inventory for this allocation. Used by GDS and direct channels to serve current seat availability to booking agents.',
    `bilateral_agreement_reference` STRING COMMENT 'Human-readable external reference number or code of the bilateral codeshare/interline agreement (e.g., contract number from the commercial agreement). Stored for operational traceability; the full agreement detail is held in the bilateral_agreement master.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this codeshare allocation record was first created in the AltĂ©a Inventory system, representing the business event of the allocation being established.',
    `days_of_operation` STRING COMMENT 'IATA-standard days-of-week string indicating on which days of the week this allocation applies within the effective date range (e.g., 1234567 = daily, 135 = Mon/Wed/Fri). Encoded as ISO weekday numbers 1=Monday through 7=Sunday.. Valid values are `^[1-7]{1,7}$`',
    `destination_iata_code` STRING COMMENT 'Three-letter IATA airport code for the arrival airport of the operating flight segment covered by this allocation (e.g., CDG, SIN, ORD).. Valid values are `^[A-Z]{3}$`',
    `effective_from` DATE COMMENT 'First date from which this codeshare allocation record is valid and active, as defined in the bilateral agreement. Supports seasonal schedule periods aligned with IATA scheduling seasons.',
    `effective_until` DATE COMMENT 'Last date through which this codeshare allocation record is valid, as defined in the bilateral agreement. Null for open-ended allocations. Aligns with IATA scheduling season end dates.',
    `fare_class_bucket` STRING COMMENT 'IATA booking class (RBD â€” Reservation Booking Designator) within the cabin to which this allocation is mapped in AltĂ©a Inventory (e.g., Y, B, M, Q, V). Determines the yield tier at which the marketing carriers seats are ring-fenced.. Valid values are `^[A-Z]{1,2}$`',
    `flight_date` DATE COMMENT 'Scheduled departure date of the operating flight for which this codeshare allocation applies. Combined with the operating flight number, uniquely identifies the flight-date instance.',
    `gds_availability_indicator` BOOLEAN COMMENT 'Flag indicating whether the marketing carriers availability under this allocation is published and visible in Global Distribution Systems (GDS) such as Amadeus, Sabre, and Travelport. When False, the allocation is restricted to direct or NDC channels only.',
    `interline_indicator` BOOLEAN COMMENT 'Flag indicating whether this allocation is governed by an interline ticketing agreement (True) rather than a pure codeshare arrangement (False). Interline allocations follow IATA BSP/ARC settlement rules.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this codeshare allocation record, such as a change to seat counts, thresholds, or status. Supports audit trail and change tracking in the Silver layer.',
    `last_seat_date` DATE COMMENT 'Latest date on which the marketing carrier may sell the last available seat under this allocation before the booking window closes. May differ from the flight date due to advance purchase restrictions in the bilateral.',
    `marketing_carrier_code` BIGINT COMMENT 'Reference to the partner airline that markets and sells seats under its own flight designator code on the operating carriers flight. The marketing carrier holds this allocation.',
    `marketing_flight_number` STRING COMMENT 'IATA-format flight designator under which the marketing carrier sells the codeshare seats (e.g., BA5678). This is the flight number visible to passengers booking through the marketing carrier.. Valid values are `^[A-Z]{2}[0-9]{1,4}[A-Z]?$`',
    `maximum_seat_threshold` STRING COMMENT 'Hard upper limit on the number of seats the marketing carrier may sell on this flight-date and cabin, enforced by AltĂ©a Inventory to prevent over-allocation beyond the bilateral agreement cap.',
    `minimum_seat_threshold` STRING COMMENT 'Minimum number of seats guaranteed to the marketing carrier that the operating carrier must hold available regardless of overall flight demand. Relevant for block-space and hybrid allocation types. Null for pure free-flow allocations.',
    `operating_flight_number` STRING COMMENT 'IATA-format flight designator of the operating carrier (e.g., AA1234). Identifies the physical flight on which the codeshare seats are allocated.. Valid values are `^[A-Z]{2}[0-9]{1,4}[A-Z]?$`',
    `origin_iata_code` STRING COMMENT 'Three-letter IATA airport code for the departure airport of the operating flight segment covered by this allocation (e.g., LHR, JFK, DXB).. Valid values are `^[A-Z]{3}$`',
    `overbooking_factor` DECIMAL(18,2) COMMENT 'Multiplier applied to the authorized seat count to permit controlled overbooking of the marketing carriers allocation (e.g., 1.0500 = 5% overbooking). Managed by the revenue management system in alignment with Sabre AirVision overbooking controls.',
    `prorate_agreement_code` STRING COMMENT 'Code referencing the revenue proration agreement between the operating and marketing carriers that governs how ticket revenue is split for seats sold under this codeshare allocation. Aligns with IATA BSP prorate rules.',
    `release_date` DATE COMMENT 'Date on which any unsold seats in a block-space allocation are automatically released back to the operating carriers general inventory pool for unrestricted sale. Null for free-flow allocations where no block is held.',
    `release_days_prior` STRING COMMENT 'Number of days before scheduled departure at which unsold block-space seats are automatically released to the operating carriers open inventory. Derived from the bilateral agreement terms and used to compute release_date.',
    `remarks` STRING COMMENT 'Free-text operational notes or remarks associated with this codeshare allocation, such as special handling instructions, commercial exceptions, or temporary override justifications entered by inventory controllers.',
    `revenue_share_percentage` DECIMAL(18,2) COMMENT 'Percentage of ticket revenue attributable to the operating carrier for seats sold by the marketing carrier under this allocation, as stipulated in the bilateral prorate agreement. Commercially sensitive.',
    `seats_available` STRING COMMENT 'Current number of seats remaining available for sale by the marketing carrier under this allocation (authorized_seat_count minus seats_sold, subject to overbooking controls). Reflects the real-time availability figure published to GDS and direct channels.',
    `seats_sold` STRING COMMENT 'Current count of seats already sold or confirmed by the marketing carrier against this allocation as of the last inventory snapshot. Used to compute remaining availability and monitor allocation utilisation.',
    CONSTRAINT pk_codeshare_allocation PRIMARY KEY(`codeshare_allocation_id`)
) COMMENT 'Master entity governing the seat block or free-flow inventory allocation granted to a codeshare or interline partner airline on a specific flight-date and cabin. Captures the operating carrier flight, the marketing carrier code, allocation type (block space vs. free-flow), authorized seat count, minimum/maximum thresholds, and the bilateral agreement reference. Ensures partner inventory is correctly ring-fenced within the host carriers AltĂ©a Inventory.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`inventory_leg` (
    `inventory_leg_id` BIGINT COMMENT 'Unique surrogate identifier for the inventory leg record within the Amadeus AltĂ©a Inventory system. Serves as the primary key for this entity in the Silver Layer lakehouse.',
    `aircraft_type_id` BIGINT COMMENT 'Foreign key linking to fleet.aircraft_type. Business justification: Revenue management systems configure fare class bucket authorization limits based on aircraft types physical capacity, cabin configuration, and range. Inventory leg planning requires structured refer',
    `flight_inventory_id` BIGINT COMMENT 'Reference to the parent flight inventory record that owns this leg. Supports multi-leg itinerary nesting and through-availability calculations within the inventory domain.',
    `arrival_terminal` STRING COMMENT 'Terminal identifier at the destination airport where this leg arrives (e.g., T2, T4, C). Used for connecting passenger MCT validation and ground handling coordination.',
    `authorized_capacity` STRING COMMENT 'Revenue management-approved total booking authorization for this leg, incorporating overbooking allowances above physical seat capacity. Set by Sabre AirVision Revenue Management and consumed by AltĂ©a Inventory for availability control.',
    `availability_snapshot_datetime` TIMESTAMP COMMENT 'UTC timestamp of the most recent real-time availability snapshot for this leg as published to GDS and direct booking channels. Supports audit of availability state at a point in time and feeds through-availability calculations.',
    `booked_count` STRING COMMENT 'Current total number of confirmed bookings (Pax) held against this leg across all fare classes and cabins. Updated in real time by the Amadeus AltĂ©a PSS as reservations are created, modified, or cancelled.',
    `cabin_configuration_code` STRING COMMENT 'Identifier for the specific cabin layout configuration assigned to this leg (e.g., Y-only, J/Y, F/J/Y). Links to the cabin configuration master to determine per-cabin seat counts and fare class bucket assignments.',
    `codeshare_blocked_count` STRING COMMENT 'Number of seats allocated to codeshare partner airlines on this operating leg. Represents inventory carved out for marketing carrier partners under codeshare agreements, reducing net availability for the operating carrier.',
    `codeshare_indicator` BOOLEAN COMMENT 'Flag indicating whether this leg is operated under a codeshare agreement, meaning one or more marketing carriers sell seats on this operating leg under their own flight numbers. True = codeshare arrangements exist for this leg.',
    `created_timestamp` TIMESTAMP COMMENT 'UTC timestamp when this inventory leg record was first created in the system, either by schedule publication or manual entry. Provides the audit trail creation anchor for data lineage and compliance purposes.',
    `departure_slot_time` TIMESTAMP COMMENT 'Allocated airport departure slot time (UTC) assigned by the slot coordinator for this leg at the origin airport. May differ from scheduled departure time. Null for airports without slot coordination (non-Level 2/3 airports).',
    `departure_terminal` STRING COMMENT 'Terminal identifier at the origin airport from which this leg departs (e.g., T1, T5, B). Used for passenger wayfinding, ground handling coordination, and SITA airport management integration.',
    `destination_airport_code` STRING COMMENT 'Three-letter IATA airport code for the arrival airport of this inventory leg (e.g., LAX, CDG, SIN). Defines the physical destination point of the leg for inventory, pricing, and slot management.. Valid values are `^[A-Z]{3}$`',
    `flight_number` STRING COMMENT 'The operating carriers flight number for this leg, combining the IATA carrier code and numeric designator (e.g., AA101, LH400). Used as the primary commercial identifier for the flight leg in GDS, OTA, and direct channels.. Valid values are `^[A-Z0-9]{2}[0-9]{1,4}[A-Z]?$`',
    `group_blocked_count` STRING COMMENT 'Number of seats currently blocked and held for group bookings on this leg. Reduces the net availability exposed to individual GDS and direct channel requests.',
    `interline_indicator` BOOLEAN COMMENT 'Flag indicating whether this leg is eligible for interline ticketing, allowing passengers to be ticketed on a single document across multiple carriers. True = interline agreements apply to this leg.',
    `inventory_close_datetime` TIMESTAMP COMMENT 'Date and time (UTC) when inventory for this leg was closed to new bookings. Typically triggered at departure or by revenue management closure rules. Null if inventory is still open.',
    `inventory_open_datetime` TIMESTAMP COMMENT 'Date and time (UTC) when inventory for this leg was first opened for sale across GDS and direct channels. Marks the start of the revenue management availability window.',
    `irop_indicator` BOOLEAN COMMENT 'Flag indicating whether this leg is currently subject to an Irregular Operations (IROP) event such as a delay, cancellation, diversion, or equipment swap. True = IROP condition active. Triggers passenger re-accommodation workflows in Amadeus AltĂ©a.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'UTC timestamp of the most recent modification to this inventory leg record, including availability updates, status changes, capacity adjustments, or schedule revisions. Essential for incremental ETL processing and Silver Layer change detection.',
    `leg_status` STRING COMMENT 'Current operational and inventory lifecycle status of this leg. active â€” open for sale; cancelled â€” flight cancelled, inventory closed; diverted â€” flight diverted to alternate airport; suspended â€” temporarily removed from sale; closed â€” inventory closed post-departure.. Valid values are `active|cancelled|diverted|suspended|closed`',
    `load_factor` DECIMAL(18,2) COMMENT 'Current load factor for this leg expressed as a percentage: (booked_count / total_seat_capacity) Ă— 100. Key revenue management KPI representing the percentage of available seats filled. Updated in real time as bookings change.',
    `operating_carrier_code` STRING COMMENT 'Two-character IATA airline designator code of the carrier physically operating this flight leg (e.g., AA, LH, EK). Distinguishes the operating carrier from any marketing/codeshare carrier.. Valid values are `^[A-Z0-9]{2}$`',
    `operating_day_of_week` STRING COMMENT 'IATA day-of-week code on which this leg operates, where 1=Monday through 7=Sunday per IATA SSIM convention. Used for schedule frequency analysis and inventory pattern matching. [ENUM-REF-CANDIDATE: 1|2|3|4|5|6|7 â€” 7 candidates stripped; promote to reference product]',
    `origin_airport_code` STRING COMMENT 'Three-letter IATA airport code for the departure airport of this inventory leg (e.g., JFK, LHR, DXB). Defines the physical origin point of the leg for inventory, pricing, and slot management.. Valid values are `^[A-Z]{3}$`',
    `overbooking_factor` DECIMAL(18,2) COMMENT 'The overbooking multiplier applied to physical seat capacity for this leg, expressed as a percentage above 100 (e.g., 105.50 means 5.5% overbooking). Derived from Sabre AirVision Revenue Management no-show and cancellation forecasting models.',
    `schedule_period_code` STRING COMMENT 'IATA seasonal schedule period code under which this leg is published (e.g., W24 for Winter 2024, S25 for Summer 2025). Aligns with IATA SSIM scheduling seasons for slot coordination and network planning.',
    `scheduled_arrival_datetime` TIMESTAMP COMMENT 'Scheduled gate arrival date and time for this leg in UTC (ISO 8601 format). Represents the planned OOOI In time used for connection logic, MCT calculations, and inventory closure triggers.',
    `scheduled_block_hours` DECIMAL(18,2) COMMENT 'Planned block time for this leg in decimal hours, measured from scheduled gate departure (Out) to scheduled gate arrival (In). Block hours are the primary unit for aircraft utilization, crew duty time, and cost accounting (CASK calculations).',
    `scheduled_departure_datetime` TIMESTAMP COMMENT 'Scheduled gate departure date and time for this leg in UTC (ISO 8601 format). Represents the planned OOOI Out time used for inventory availability windows, GDS display, and OTP measurement.',
    `scheduled_flight_distance_km` STRING COMMENT 'Great-circle distance of this leg in kilometres between origin and destination airports. Used in RPK (Revenue Passenger Kilometre) and ASK (Available Seat Kilometre) calculations, yield analysis, and CORSIA carbon emissions reporting.',
    `sequence_number` STRING COMMENT 'Ordinal position of this physical leg within the parent flight inventory record (e.g., 1 for the first leg, 2 for the second leg of a multi-leg service). Used to reconstruct itinerary order and support through-availability logic.',
    `service_type_code` STRING COMMENT 'IATA single-character service type code indicating the nature of the flight service (e.g., J for scheduled passenger, F for scheduled freight, C for charter). Drives inventory partitioning between passenger and cargo domains.. Valid values are `^[A-Z]{1}$`',
    `through_availability_indicator` BOOLEAN COMMENT 'Flag indicating whether this leg participates in through-availability calculations, allowing connecting itinerary availability to be computed across multiple legs without individual leg-level availability checks. True = through-availability enabled.',
    `total_seat_capacity` STRING COMMENT 'Total number of sellable passenger seats on this leg across all cabins, as configured in the inventory system for the assigned aircraft type. This is the gross capacity before overbooking authorization is applied.',
    `waitlisted_count` STRING COMMENT 'Number of passengers currently on the waitlist for this leg, pending availability opening due to cancellations or capacity adjustments. Managed within Amadeus AltĂ©a Inventory waitlist queues.',
    `wet_lease_indicator` BOOLEAN COMMENT 'Flag indicating whether this leg is operated under a wet lease (ACMI) arrangement, where the aircraft, crew, maintenance, and insurance are provided by a lessor airline. Affects operating carrier attribution and regulatory reporting.',
    CONSTRAINT pk_inventory_leg PRIMARY KEY(`inventory_leg_id`)
) COMMENT 'Master entity representing a single physical flight leg as the unit of inventory management, distinct from the commercial flight segment. Captures origin and destination airport IATA codes, scheduled departure and arrival datetimes, operating carrier, flight number, service type, and the link to the parent flight inventory record. Supports multi-leg itinerary inventory nesting and through-availability calculations.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`segment` (
    `segment_id` BIGINT COMMENT 'Unique surrogate identifier for the commercial Origin-Destination (O&D) inventory segment record in the Amadeus AltĂ©a Inventory system. Primary key for this entity.',
    `aircraft_type_id` BIGINT COMMENT 'Foreign key linking to fleet.aircraft_type. Business justification: Segment-level inventory control and nesting logic depend on aircraft types seat capacity and cabin class distribution. GDS availability calculations and codeshare seat allocation require aircraft typ',
    `cabin_class_id` BIGINT COMMENT 'Foreign key linking to inventory.cabin_class. Business justification: inventory_segment represents a commercial O&D segment sold in a specific cabin class. cabin_class is the reference master for cabin definitions. This FK links segment records to the cabin master. cabi',
    `inventory_leg_id` BIGINT COMMENT 'Reference to the underlying physical inventory leg (flight leg) from which this commercial segment derives its availability. A segment may span one or more legs in a connecting itinerary.',
    `scheduled_flight_id` BIGINT COMMENT 'Reference to the scheduled flight record associated with this inventory segment, linking to the flight operations domain for operational context.',
    `authorized_capacity` STRING COMMENT 'Total number of seats authorized for sale on this segment in the specified cabin and booking class, including any overbooking allowance approved by revenue management. This is the gross sellable inventory before netting sold seats.',
    `availability_control_method` STRING COMMENT 'Method used to control seat availability for this segment: leg_based = availability derived from individual leg bucket counts; od_based = availability controlled at the O&D segment level using virtual nesting; hybrid = combination of leg and O&D controls.. Valid values are `leg_based|od_based|hybrid`',
    `availability_snapshot_time` TIMESTAMP COMMENT 'Timestamp (UTC) at which the current availability figures (seats_sold, seats_available, load_factor) were last refreshed from the Amadeus AltĂ©a Inventory system. Critical for GDS cache synchronization and real-time availability accuracy.',
    `booking_class` STRING COMMENT 'Single-letter IATA Reservation Booking Designator (RBD) representing the fare class bucket for this segment (e.g., Y, B, M, Q, V, W). Directly controls availability nesting and revenue management yield optimization in Sabre AirVision and Amadeus AltĂ©a.. Valid values are `^[A-Z]{1}$`',
    `codeshare_seat_allocation` STRING COMMENT 'Number of seats allocated to the marketing carrier under a block-space codeshare agreement for this segment. Applicable only when codeshare_type = block_space. Null for free-flow or non-codeshare segments.',
    `codeshare_type` STRING COMMENT 'Type of codeshare arrangement governing inventory allocation for this segment: free_flow = marketing carrier draws from operating carriers open inventory; block_space = a fixed seat block is allocated to the marketing carrier; none = not a codeshare segment.. Valid values are `free_flow|block_space|none`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp (UTC) when this inventory segment record was first created in the system, typically when the flight schedule was loaded into Amadeus AltĂ©a Inventory for the season.',
    `departure_date` DATE COMMENT 'Scheduled departure date of the segment at the origin airport in local time (yyyy-MM-dd). Used as the primary date dimension for inventory availability queries and revenue management yield optimization.',
    `destination_airport_code` STRING COMMENT 'Three-letter IATA airport code for the destination station of this commercial O&D segment as sold to the passenger. Defines the arrival point of the sellable unit.. Valid values are `^[A-Z]{3}$`',
    `fare_basis_code` STRING COMMENT 'IATA fare basis code identifying the specific fare product associated with this inventory segment (e.g., YLOWUS, BAPOW). Governs fare rules, restrictions, and the booking class bucket to which availability is mapped.. Valid values are `^[A-Z0-9]{1,8}$`',
    `gds_availability_code` STRING COMMENT 'Availability status code published to Global Distribution Systems (GDS) such as Amadeus, Sabre, and Travelport for this segment and booking class. Standard codes include numeric seat counts (0-9) or alpha codes (A=available, C=closed, L=waitlist) per IATA AIRIMP standards.. Valid values are `^[A-Z0-9]{1,2}$`',
    `group_seats_held` STRING COMMENT 'Number of seats currently held under group booking reservations for this segment. Group holds reduce available inventory and are subject to release deadlines managed by the group desk.',
    `interline_eligible` BOOLEAN COMMENT 'Indicates whether this inventory segment is eligible for interline ticketing agreements, allowing passengers to book connecting itineraries across multiple carriers on a single ticket. Governed by bilateral interline agreements and IATA BSP/ARC settlement rules.',
    `load_factor` DECIMAL(18,2) COMMENT 'Current load factor for this inventory segment expressed as a percentage of physical cabin capacity that is sold or confirmed (seats_sold / physical_capacity * 100). Key performance indicator for revenue management and capacity planning. Note: this is a point-in-time snapshot value, not a computed aggregate.',
    `marketed_flight_number` STRING COMMENT 'The IATA-format flight number as sold to passengers and published in GDS channels (e.g., AA1234). For codeshare segments, this is the marketing carriers flight number, which may differ from the operating carriers flight number.. Valid values are `^[A-Z]{2}[0-9]{1,4}$`',
    `marketing_carrier_code` STRING COMMENT 'Two-character IATA airline designator of the carrier that markets and sells this segment to passengers. For codeshare flights, this is the airline whose flight number appears on the ticket.. Valid values are `^[A-Z0-9]{2}$`',
    `min_connecting_time_minutes` STRING COMMENT 'Minimum Connecting Time (MCT) in minutes required at the connecting airport for this segment to be valid in a connecting itinerary. Enforced during availability display and booking to prevent infeasible connections. Sourced from IATA SSIM MCT tables.',
    `nesting_level` STRING COMMENT 'Hierarchical nesting level of this booking class within the cabins availability nesting structure (e.g., 1=highest yield class, 10=lowest yield class). Governs through-availability rules: higher-level classes inherit availability from lower-level buckets per revenue management nesting policy.',
    `operating_carrier_code` STRING COMMENT 'Two-character IATA airline designator of the carrier that physically operates the aircraft for this segment. Differs from marketing_carrier_code on codeshare flights.. Valid values are `^[A-Z0-9]{2}$`',
    `origin_airport_code` STRING COMMENT 'Three-letter IATA airport code for the origin station of this commercial O&D segment as sold to the passenger. Defines the departure point of the sellable unit.. Valid values are `^[A-Z]{3}$`',
    `overbooking_limit` STRING COMMENT 'Maximum number of seats that may be sold beyond the physical cabin capacity for this segment, as authorized by revenue management overbooking controls. Expressed as an absolute seat count above physical capacity.',
    `overbooking_rate` DECIMAL(18,2) COMMENT 'Overbooking authorization expressed as a percentage above physical cabin capacity (e.g., 5.00 = 5% overbooking). Used by revenue management to calibrate no-show risk models and optimize load factor.',
    `sale_close_date` DATE COMMENT 'Date after which this inventory segment is no longer available for new bookings. Typically set to the departure date or earlier based on advance purchase restrictions and revenue management close-out rules.',
    `sale_open_date` DATE COMMENT 'Date from which this inventory segment is open for sale in GDS and direct booking channels. Defines the advance purchase window start for revenue management and distribution control.',
    `scheduled_arrival_time` TIMESTAMP COMMENT 'Scheduled arrival date and time of the segment at the destination airport in UTC (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for MCT enforcement and connecting itinerary feasibility validation.',
    `scheduled_departure_time` TIMESTAMP COMMENT 'Scheduled departure date and time of the segment at the origin airport in UTC (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for precise GDS availability display and MCT (Minimum Connecting Time) enforcement calculations.',
    `season_code` STRING COMMENT 'IATA scheduling season code for this inventory segment (e.g., S25 = Summer 2025, W24 = Winter 2024). Aligns inventory records with the IATA Standard Schedules Information Manual (SSIM) scheduling seasons used for slot management and route planning.. Valid values are `^[SW][0-9]{2}$`',
    `seats_available` STRING COMMENT 'Current count of seats available for sale on this segment, computed as authorized_capacity minus seats_sold minus seats_blocked. This is the real-time availability figure published to GDS and direct channels.',
    `seats_blocked` STRING COMMENT 'Number of seats held back from general sale for operational purposes such as crew positioning, group holds, codeshare allocations, or special service requests (SSR). Reduces net available inventory without being sold.',
    `seats_sold` STRING COMMENT 'Number of seats currently confirmed as sold (booked and ticketed) on this inventory segment. Updated in real-time from the Passenger Service System (PSS) as bookings are made or cancelled.',
    `segment_status` STRING COMMENT 'Current availability status of this inventory segment as published to GDS and direct booking channels. open = seats available for sale; closed = no availability; waitlisted = demand exceeds supply, waitlist active; cancelled = flight/segment cancelled; suspended = temporarily removed from sale.. Valid values are `open|closed|waitlisted|cancelled|suspended`',
    `segment_type` STRING COMMENT 'Classification of the commercial segment by its operational and commercial structure: direct = single leg O&D; connecting = multi-leg through-availability segment; codeshare = marketed by partner airline; interline = cross-carrier ticketing agreement; virtual = constructed availability for display purposes.. Valid values are `direct|connecting|codeshare|interline|virtual`',
    `through_availability_flag` BOOLEAN COMMENT 'Indicates whether this segment participates in through-availability nesting, meaning its availability is derived from the aggregated availability of underlying leg buckets rather than being independently controlled. True = through-availability applies.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp (UTC) of the most recent update to this inventory segment record, including availability changes, overbooking adjustments, or status transitions. Used for incremental data pipeline processing in the Databricks Silver layer.',
    `waitlist_count` STRING COMMENT 'Number of passengers currently on the waitlist for this inventory segment and booking class. Used by revenue management to assess latent demand and inform overbooking and upgrade decisions.',
    CONSTRAINT pk_segment PRIMARY KEY(`segment_id`)
) COMMENT 'Master entity representing a commercial O&D (origin-destination) segment as sold to passengers, which may span one or more physical inventory legs. Captures the marketed flight number, O&D city pair, cabin, fare basis, and the through-availability nesting rules that govern how segment availability is derived from underlying leg buckets. Critical for connecting-itinerary inventory control and MCT (Minimum Connecting Time) enforcement.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`availability_snapshot` (
    `availability_snapshot_id` BIGINT COMMENT 'Unique surrogate identifier for each point-in-time availability snapshot record captured for a flight inventory record.',
    `cabin_class_id` BIGINT COMMENT 'Foreign key linking to inventory.cabin_class. Business justification: availability_snapshot captures point-in-time availability state for a specific cabin class. cabin_class is the reference master for cabin definitions. This FK links snapshot records to the cabin maste',
    `fare_class_bucket_id` BIGINT COMMENT 'Foreign key linking to inventory.fare_class_bucket. Business justification: availability_snapshot captures availability state for a specific fare class bucket (RBD). fare_class_bucket is the master entity for RBD buckets. This FK links snapshot records to the bucket master. b',
    `flight_inventory_id` BIGINT COMMENT 'Reference to the flight inventory record (flight-date-leg combination) for which this availability snapshot was captured. Links to the parent inventory entity in Amadeus AltĂ©a.',
    `scheduled_flight_id` BIGINT COMMENT 'Reference to the scheduled flight (operating flight number and departure date) associated with this snapshot, enabling direct join to flight operations data.',
    `advance_purchase_days` STRING COMMENT 'The minimum number of days before departure that a booking must be made to qualify for this fare class bucket at snapshot time. A fare restriction parameter that governs bucket eligibility.',
    `authorized_capacity` STRING COMMENT 'The total number of seats authorized for sale in this cabin at snapshot time, incorporating the overbooking factor applied to physical cabin capacity. Represents the effective sellable ceiling for the cabin.',
    `availability_code` STRING COMMENT 'The availability indicator code broadcast to GDS channels at snapshot time (e.g., A = available, L = limited, C = closed, R = request). Follows IATA/GDS standard availability display codes used in Amadeus, Sabre, and Travelport.. Valid values are `^[A-Z0-9]{1,2}$`',
    `bucket_status` STRING COMMENT 'The availability status of this fare class bucket as broadcast to GDS and direct channels at snapshot time. Open = seats available for sale; Closed = bucket closed by RM; Waitlist = no seats but waitlist accepted; Request_only = availability subject to manual approval.. Valid values are `open|closed|waitlist|request_only`',
    `channel_restriction_flag` BOOLEAN COMMENT 'Indicates whether this fare class bucket has channel-specific distribution restrictions applied at snapshot time (e.g., web-only, GDS-excluded, direct-only). True = one or more channel restrictions are active.',
    `codeshare_seats_allocated` STRING COMMENT 'The number of seats in this fare class bucket allocated to codeshare partner airlines at snapshot time. Represents inventory blocked for partner distribution and reduces the seats available to the operating carriers own channels.',
    `created_timestamp` TIMESTAMP COMMENT 'The UTC timestamp when this snapshot record was first written to the Silver layer data store. Serves as the audit creation timestamp for data lineage and ETL traceability. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'The ISO 4217 three-letter currency code in which the rm_bid_price is denominated (e.g., USD, EUR, GBP). Necessary for multi-currency RM analysis across international routes.. Valid values are `^[A-Z]{3}$`',
    `days_before_departure` STRING COMMENT 'The number of days between the snapshot timestamp and the scheduled departure date at the time of capture. A critical dimension for revenue management booking curve analysis and demand forecasting model training.',
    `departure_date` DATE COMMENT 'The scheduled local departure date of the flight for which availability is being snapshotted. Used as a primary partitioning and filtering dimension for historical availability analysis.',
    `destination_airport_code` STRING COMMENT 'Three-letter IATA airport code for the arrival station of the flight leg being snapshotted (e.g., LAX, CDG). Denormalized for direct availability analysis by destination market.. Valid values are `^[A-Z]{3}$`',
    `flight_number` STRING COMMENT 'The IATA-format operating flight number (e.g., AA101, BA0293) at the time of the snapshot. Denormalized here for direct query access without joining to the flight schedule table.. Valid values are `^[A-Z0-9]{2,3}[0-9]{1,4}[A-Z]?$`',
    `gds_broadcast_timestamp` TIMESTAMP COMMENT 'The UTC timestamp at which this availability state was broadcast to Global Distribution Systems (Amadeus, Sabre, Travelport). Used for GDS audit trails and latency analysis between snapshot capture and distribution. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `group_seats_blocked` STRING COMMENT 'The number of seats in this cabin blocked for confirmed or tentative group bookings at snapshot time. Group blocks reduce the net availability for individual (PNR-level) bookings.',
    `is_active_snapshot` BOOLEAN COMMENT 'Indicates whether this record represents the most current (latest) availability snapshot for the given flight inventory record and fare class bucket combination. True = this is the current state; False = superseded by a later snapshot. Supports efficient current-state queries without full history scans.',
    `load_factor` DECIMAL(18,2) COMMENT 'The cabin-level load factor at snapshot time, expressed as a ratio of seats sold to physical cabin capacity (e.g., 0.8500 = 85%). A key revenue management KPI used to assess fill rate and trigger yield optimization actions. Calculated as seats_sold / physical_capacity.',
    `minimum_stay_required` BOOLEAN COMMENT 'Indicates whether a minimum stay condition (e.g., Saturday night stay) is required for bookings in this fare class bucket at snapshot time. True = minimum stay restriction is active on this bucket.',
    `origin_airport_code` STRING COMMENT 'Three-letter IATA airport code for the departure station of the flight leg being snapshotted (e.g., JFK, LHR). Denormalized for direct availability analysis by origin market.. Valid values are `^[A-Z]{3}$`',
    `overbooking_factor` DECIMAL(18,2) COMMENT 'The overbooking multiplier applied to this cabin at snapshot time, expressed as a ratio (e.g., 1.0500 = 5% overbooking above physical capacity). Set by revenue management to account for expected no-shows and cancellations.',
    `physical_capacity` STRING COMMENT 'The actual number of physical seats installed in this cabin on the aircraft assigned to this flight at snapshot time. Reflects the aircraft configuration at the time of capture, which may differ from the scheduled configuration.',
    `rm_bid_price` DECIMAL(18,2) COMMENT 'The revenue management bid price (opportunity cost threshold) for this cabin at snapshot time, expressed in the operating currency. A booking is accepted only if its revenue exceeds the bid price. Core RM optimization output from Sabre AirVision.',
    `rm_forecast_demand` STRING COMMENT 'The revenue management systems demand forecast (unconstrained) for this fare class bucket at the time of the snapshot, expressed as number of expected bookings. Sourced from Sabre AirVision RM forecasting module. Used for model training and forecast accuracy measurement.',
    `seats_authorized` STRING COMMENT 'The maximum number of seats authorized by revenue management for sale in this fare class bucket (the bucket cap set by the RM system). Distinct from physical capacity; reflects yield optimization controls from Sabre AirVision.',
    `seats_available` STRING COMMENT 'The number of seats available for sale in this fare class bucket at the moment of the snapshot. A value of zero indicates the bucket is closed. This is the primary sellable inventory count broadcast to GDS and direct channels.',
    `seats_held` STRING COMMENT 'Number of seats in this bucket currently held under option or waitlist status (not yet confirmed) at snapshot time. Represents tentative demand that may convert to confirmed bookings.',
    `seats_sold` STRING COMMENT 'The cumulative number of confirmed bookings (paid and held) in this fare class bucket at the time of the snapshot. Includes codeshare and interline bookings allocated to this bucket.',
    `snapshot_sequence_number` STRING COMMENT 'An ordinal sequence number for snapshots taken for the same flight inventory record and fare class bucket, ordered by snapshot_timestamp ascending. Enables reconstruction of the full availability history and booking curve for a given flight-bucket combination.',
    `snapshot_timestamp` TIMESTAMP COMMENT 'The precise UTC date and time at which this availability state was captured. Serves as the primary temporal anchor for point-in-time analysis and GDS broadcast audit. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `source_system_code` STRING COMMENT 'Identifies the operational system that generated or triggered this availability snapshot. ALTEA = Amadeus AltĂ©a Inventory (primary PSS); SABRE_AV = Sabre AirVision RM override; NETLINE = Lufthansa Systems NetLine/Ops operational change; MANUAL = manually entered override.. Valid values are `ALTEA|SABRE_AV|NETLINE|MANUAL`',
    `trigger_reason` STRING COMMENT 'The business event or condition that caused this snapshot to be taken. Distinguishes between routine scheduled captures, threshold-driven captures (booking or cancellation crossing a bucket boundary), manual revenue management overrides, reaccommodation events (IROPs), and overbooking adjustments. [ENUM-REF-CANDIDATE: scheduled|booking_threshold|cancellation_threshold|manual_override|reaccommodation|overbooking_adjustment â€” promote to reference product]. Valid values are `scheduled|booking_threshold|cancellation_threshold|manual_override|reaccommodation|overbooking_adjustment`',
    `updated_timestamp` TIMESTAMP COMMENT 'The UTC timestamp when this snapshot record was last modified in the Silver layer (e.g., due to late-arriving corrections or reprocessing). Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `upgrade_seats_used` STRING COMMENT 'The number of seats in this cabin occupied by passengers who have been upgraded from a lower cabin class (operational, complimentary, or mileage-based upgrades) at snapshot time. Affects net revenue yield for the cabin.',
    `waitlist_count` STRING COMMENT 'The number of passengers currently on the waitlist for this fare class bucket at snapshot time. A non-zero value when bucket_status is waitlist or closed, indicating latent demand that may be cleared if cancellations occur.',
    CONSTRAINT pk_availability_snapshot PRIMARY KEY(`availability_snapshot_id`)
) COMMENT 'Transactional point-in-time capture of the full availability state across all fare class buckets for a flight inventory record, taken at scheduled intervals or triggered by significant booking events. Used for historical availability analysis, revenue management model training, and audit of GDS availability broadcasts. Stores the complete bucket-level seat count array, load factor at snapshot time, and the trigger reason (scheduled, booking threshold, manual override).';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`bucket_adjustment` (
    `bucket_adjustment_id` BIGINT COMMENT 'Unique surrogate identifier for each inventory bucket adjustment audit record in the silver layer lakehouse. Primary key for this transactional audit entity.',
    `cabin_class_id` BIGINT COMMENT 'Foreign key linking to inventory.cabin_class. Business justification: bucket_adjustment records changes to inventory state affecting a specific cabin class. cabin_class is the reference master for cabin definitions. This FK links adjustment records to the cabin master. ',
    `employee_id` BIGINT COMMENT 'Employee or system account identifier of the analyst or automated process that initiated this inventory adjustment. Populated for manual overrides and analyst-driven actions; may be a system service account for automated RM adjustments. Confidential as it identifies internal workforce activity.',
    `fare_class_bucket_id` BIGINT COMMENT 'Reference to the fare class bucket (booking class) whose capacity or status was adjusted. Links to the fare class bucket master defining the booking class code and cabin association.',
    `forecast_id` BIGINT COMMENT 'Reference to the revenue management demand forecast record in Sabre AirVision that triggered or informed this automated inventory adjustment. Links the audit record to the RM optimization decision for post-departure forecast accuracy analysis.',
    `scheduled_flight_id` BIGINT COMMENT 'Reference to the specific flight leg whose inventory was adjusted. Identifies the flight-date-origin-destination combination affected by this adjustment.',
    `adjustment_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to this inventory adjustment event, used for cross-system traceability between AltĂ©a Inventory, Sabre AirVision Revenue Management, and GDS channels.. Valid values are `^ADJ-[A-Z0-9]{8,20}$`',
    `adjustment_scope` STRING COMMENT 'Defines the granularity level at which this inventory adjustment was applied: flight (entire flight stop-sale or reopen), cabin (all buckets within a cabin class), or bucket (a specific fare class booking designator). Determines which of the cabin_code and booking_class_code fields are applicable.. Valid values are `flight|cabin|bucket`',
    `adjustment_status` STRING COMMENT 'Current lifecycle state of this adjustment record. applied indicates the change is live in inventory; reversed indicates a subsequent correction nullified this action; superseded indicates a later adjustment replaced this one.. Valid values are `applied|pending|reversed|failed|superseded`',
    `adjustment_type` STRING COMMENT 'Categorical discriminator identifying the nature of the inventory control action applied. Drives downstream revenue analysis and audit classification. [ENUM-REF-CANDIDATE: bucket_limit_change|status_change|cabin_closure|flight_stop_sale|flight_reopen|codeshare_reallocation â€” promote to reference product]. Valid values are `bucket_limit_change|status_change|cabin_closure|flight_stop_sale|flight_reopen|codeshare_reallocation`',
    `after_authorization_level` STRING COMMENT 'The bucket authorization level (seat limit / cap) set by this adjustment. Represents the maximum number of seats authorized for sale in this booking class after the change is applied. Delta from before_authorization_level quantifies the inventory impact.',
    `after_bucket_status` STRING COMMENT 'The availability status of the fare class bucket set by this adjustment. Captures whether the bucket is now open for sale, closed, on waitlist, or request-only after the change is applied.. Valid values are `open|closed|waitlist|request_only`',
    `before_authorization_level` STRING COMMENT 'The bucket authorization level (seat limit / cap) in effect immediately before this adjustment was applied. Represents the maximum number of seats authorized for sale in this booking class prior to the change. Used for before/after delta analysis in revenue management.',
    `before_bucket_status` STRING COMMENT 'The availability status of the fare class bucket immediately before this adjustment. Captures whether the bucket was open for sale, closed, on waitlist, or request-only prior to the change.. Valid values are `open|closed|waitlist|request_only`',
    `booking_class_code` STRING COMMENT 'Single-letter IATA Reservation Booking Designator (RBD) identifying the fare class bucket affected by this adjustment (e.g., Y, B, M, Q, V, G). Null for flight-level or cabin-level adjustments that span all buckets.. Valid values are `^[A-Z]{1}$`',
    `channel_restriction` STRING COMMENT 'Specifies whether this inventory adjustment applies to all distribution channels or is restricted to a specific channel subset: GDS (Global Distribution System), direct (airline.com and mobile), or NDC (New Distribution Capability) channels only. none indicates no channel restriction is applied.. Valid values are `all_channels|gds_only|direct_only|ndc_only|none`',
    `codeshare_partner_code` STRING COMMENT 'Two-character IATA airline designator of the codeshare marketing partner whose inventory allocation is affected by this adjustment. Populated only when is_codeshare_affected is True. Used to reconcile codeshare inventory reallocation events with partner settlement.. Valid values are `^[A-Z0-9]{2}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this bucket adjustment record was first captured in the silver layer data product. Distinct from effective_timestamp which reflects the business event time. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `days_to_departure` STRING COMMENT 'Number of days between the effective_timestamp of this adjustment and the scheduled flight departure date. Critical revenue management context metric used to analyze booking curve behavior and evaluate the appropriateness of inventory control decisions at each booking horizon.',
    `destination_airport_code` STRING COMMENT 'Three-letter IATA airport code for the arrival station of the flight leg affected by this inventory adjustment (e.g., LAX, CDG). Together with origin_airport_code defines the O&D pair for revenue analysis.. Valid values are `^[A-Z]{3}$`',
    `effective_timestamp` TIMESTAMP COMMENT 'The principal real-world timestamp at which the inventory adjustment became effective in the live inventory system. This is the business event time, distinct from the audit record creation timestamp. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `flight_date` DATE COMMENT 'Scheduled departure date of the flight leg whose inventory was adjusted. Combined with flight_number provides the flight-date key used in GDS availability queries. Format: yyyy-MM-dd.',
    `flight_number` STRING COMMENT 'IATA-format airline designator and numeric flight number (e.g., AA1234) identifying the operating flight affected by this inventory adjustment. Denormalized for direct audit readability without joining to the flight entity.. Valid values are `^[A-Z]{2}[0-9]{1,4}$`',
    `initiating_system` STRING COMMENT 'Identifies the operational system or channel that triggered this inventory adjustment. Distinguishes automated revenue management actions (Sabre AirVision) from inventory system actions (AltĂ©a Inventory), operations control actions (NetLine/Ops for IROPs), and manual analyst overrides.. Valid values are `sabre_airvision|altea_inventory|manual_override|netline_ops|external_api`',
    `irop_event_reference` STRING COMMENT 'Reference identifier linking this inventory adjustment to a specific Irregular Operations (IROP) event such as a cancellation, diversion, or significant delay that necessitated inventory reprotection or stop-sale actions. Null for non-IROP-driven adjustments.',
    `is_automated` BOOLEAN COMMENT 'Indicates whether this inventory adjustment was triggered automatically by a revenue management system rule or algorithm (True) versus initiated manually by a revenue management analyst (False). Enables segregation of automated vs. manual control decisions in audit and performance analysis.',
    `is_codeshare_affected` BOOLEAN COMMENT 'Indicates whether this inventory adjustment affects codeshare inventory allocations (True) in addition to or instead of the operating carriers own inventory. When True, the codeshare_partner_code field identifies the affected marketing carrier.',
    `load_factor_at_adjustment` DECIMAL(18,2) COMMENT 'The cabin or flight load factor (percentage of seats filled) at the time this adjustment was triggered. Expressed as a decimal percentage (e.g., 0.85 = 85%). Key context metric for revenue management yield optimization analysis and threshold-triggered automation.',
    `notes` STRING COMMENT 'Supplementary free-text notes attached to this inventory adjustment record by the revenue management analyst or operations control team. May include escalation context, regulatory compliance notes, or cross-team coordination details not captured in structured fields.',
    `origin_airport_code` STRING COMMENT 'Three-letter IATA airport code for the departure station of the flight leg affected by this inventory adjustment (e.g., JFK, LHR). Used to scope the adjustment to the correct flight-leg inventory.. Valid values are `^[A-Z]{3}$`',
    `overbooking_factor_after` DECIMAL(18,2) COMMENT 'The overbooking authorization factor (as a percentage above physical capacity) set by this adjustment for this cabin/bucket. Compared against overbooking_factor_before to quantify the overbooking control change applied.',
    `overbooking_factor_before` DECIMAL(18,2) COMMENT 'The overbooking authorization factor (as a percentage above physical capacity) in effect for this cabin/bucket immediately before this adjustment. For example, 1.10 represents 110% of physical seat capacity authorized. Used to audit overbooking control decisions.',
    `reason_code` STRING COMMENT 'Standardized reason code classifying the business driver behind this inventory adjustment. Enables post-departure revenue analysis by adjustment cause. [ENUM-REF-CANDIDATE: rm_optimization|irop_reprotection|group_block|codeshare_reallocation|load_factor_threshold|schedule_change â€” promote to reference product]. Valid values are `rm_optimization|irop_reprotection|group_block|codeshare_reallocation|load_factor_threshold|schedule_change`',
    `reason_description` STRING COMMENT 'Free-text narrative providing additional context for the inventory adjustment beyond the standardized reason_code. Entered by the revenue management analyst or populated by the automated system (e.g., Load factor exceeded 85% threshold â€” closing Q class).',
    `reversal_reference_number` STRING COMMENT 'The adjustment_reference_number of the subsequent adjustment record that reversed or superseded this action. Populated only when adjustment_status is reversed or superseded. Enables full audit chain reconstruction for compliance and revenue analysis.',
    `seats_available_after` STRING COMMENT 'The count of seats available for sale in this fare class bucket immediately after this adjustment was applied. Compared against seats_available_before to measure the net availability impact on GDS and direct channel inventory.',
    `seats_available_before` STRING COMMENT 'The count of seats available for sale in this fare class bucket immediately before this adjustment was applied. Snapshot of the real-time availability figure consumed by GDS channels prior to the change.',
    `source_system_transaction_reference` STRING COMMENT 'The native transaction or message identifier assigned by the originating operational system (AltĂ©a Inventory, Sabre AirVision, or NetLine/Ops) for this adjustment event. Enables traceability back to the system-of-record for reconciliation and dispute resolution.',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording the last modification to this bucket adjustment record in the silver layer, for example when a reversal or status correction is applied. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_bucket_adjustment PRIMARY KEY(`bucket_adjustment_id`)
) COMMENT 'Transactional audit record of every manual or automated change to inventory state, including fare class bucket capacity/limit changes, bucket open/close actions, cabin closures, flight-level stop-sale events, and reopen actions. Captures before and after values, adjustment type (bucket limit change, status change, flight closure, cabin closure, stop-sale), reason code (RM optimization, IROP reprotection, group block, codeshare reallocation, load factor threshold, schedule change), the initiating system or analyst (Sabre AirVision, AltĂ©a Inventory, manual override), affected scope (flight, cabin, bucket), and effective timestamp. Provides the single authoritative audit trail of all inventory control decisions for post-departure revenue analysis and regulatory compliance.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`group_block` (
    `group_block_id` BIGINT COMMENT 'Unique surrogate identifier for the group block record in the inventory system. Primary key for this entity.',
    `cabin_class_id` BIGINT COMMENT 'Foreign key linking to inventory.cabin_class. Business justification: group_block allocates seats in a specific cabin class. cabin_class is the reference master for cabin definitions. This FK links group block records to the cabin master. cabin_code is redundant and ava',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Group bookings are often generated through marketing campaigns targeting tour operators, corporate travel programs, and event organizers. Airlines attribute group sales to campaigns for ROI measuremen',
    `catering_order_id` BIGINT COMMENT 'Foreign key linking to procurement.catering_order. Business justification: Group bookings trigger special catering orders with bulk meal requirements and custom menus. Group coordinators link blocks to catering orders for accurate provisioning and cost allocation. Essential ',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Group sales agents create and manage group blocks. Essential for sales commission calculation, performance metrics, accountability, and customer relationship management. Replaces agent_code with prope',
    `fare_class_id` BIGINT COMMENT 'Reference to the fare class bucket (booking class) under which the group block seats are held. Determines the yield and revenue management bucket impacted by this block.',
    `flight_inventory_id` BIGINT COMMENT 'Foreign key linking to inventory.flight_inventory. Business justification: group_block reserves a seat block for a group booking on a specific flight-date. flight_inventory is the master inventory record for that flight-date. This FK establishes the natural parent-child rela',
    `flight_leg_id` BIGINT COMMENT 'Reference to the specific flight-date instance on which this group block is reserved. Links to the flight schedule/operations entity.',
    `pnr_id` BIGINT COMMENT 'Reference to the master Passenger Name Record (PNR) associated with this group block. A group block is linked to a single group PNR in the Passenger Service System (PSS).',
    `block_status` STRING COMMENT 'Current lifecycle status of the group block. tentative = seats held pending confirmation; confirmed = group has committed; ticketed = tickets issued; cancelled = block released back to inventory; expired = option date passed without confirmation; waitlisted = requested but not yet allocated. [ENUM-REF-CANDIDATE: tentative|confirmed|ticketed|cancelled|expired|waitlisted â€” promote to reference product]. Valid values are `tentative|confirmed|ticketed|cancelled|expired|waitlisted`',
    `booking_class_code` STRING COMMENT 'Single-letter IATA booking class (fare class bucket) code under which the group seats are held (e.g., G for group fare class). Directly controls which revenue management bucket is debited when seats are allocated.. Valid values are `^[A-Z]{1}$`',
    `codeshare_indicator` BOOLEAN COMMENT 'Indicates whether this group block is associated with a codeshare flight operation, where the operating carrier differs from the marketing carrier. True = codeshare flight; False = own-metal operation. Affects inventory allocation and interline settlement.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this group block record was first created in the inventory system. Supports audit trail, SLA tracking, and data lineage requirements.',
    `deposit_amount` DECIMAL(18,2) COMMENT 'The monetary deposit amount required or received for this group block, expressed in fare_currency_code. Null if deposit_required is False.',
    `deposit_paid` BOOLEAN COMMENT 'Indicates whether the required deposit has been received from the group organizer. True = deposit received; False = deposit outstanding. Drives follow-up and cancellation workflows.',
    `deposit_paid_date` DATE COMMENT 'The date on which the deposit payment was received from the group organizer. Null if deposit has not been paid.',
    `deposit_required` BOOLEAN COMMENT 'Indicates whether a deposit payment is required from the group organizer to hold or confirm this group block. True = deposit required; False = no deposit required.',
    `fare_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the group_fare_amount is denominated (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `final_payment_due_date` DATE COMMENT 'The date by which the full fare payment for all ticketed seats in the group block must be settled. Distinct from the deposit due date and ticketing deadline.',
    `free_seat_ratio` DECIMAL(18,2) COMMENT 'The ratio of complimentary (free) seats granted to the group organizer relative to the total seats purchased, expressed as a decimal (e.g., 0.1000 = 1 free seat per 10 paid). Drives revenue accounting and yield calculations.',
    `free_seats_allocated` STRING COMMENT 'The actual number of complimentary (free) seats allocated to the group organizer based on the free_seat_ratio and confirmed group size. Impacts revenue accounting and load factor reporting.',
    `group_fare_amount` DECIMAL(18,2) COMMENT 'Negotiated per-seat fare amount agreed for this group block, expressed in the currency specified by fare_currency_code. Represents the contracted price per passenger for revenue accounting and settlement.',
    `group_fare_basis` STRING COMMENT 'The fare basis code applicable to the group block, defining the fare rules, restrictions, and pricing conditions under which the group seats are sold (e.g., GEXCAP, YGROUP). Aligns with IATA fare construction rules.',
    `group_name` STRING COMMENT 'The commercial or organizational name of the group for whom the seat block is reserved (e.g., Smith Wedding Party, ACME Corp Sales Conference). Used for identification and communication with the group organizer.',
    `group_type` STRING COMMENT 'Classification of the group by purpose or segment. Used for revenue management analysis, pricing strategy, and reporting. [ENUM-REF-CANDIDATE: leisure|corporate|incentive|military|religious|sports|charter â€” promote to reference product]',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The timestamp when this group block record was most recently updated in the inventory system. Used for change detection, ETL delta processing, and audit compliance.',
    `minimum_group_size` STRING COMMENT 'The minimum number of passengers required to qualify for group fare pricing on this block, as defined by the applicable fare rules. Typically 10 passengers per IATA group fare conventions.',
    `names_due_date` DATE COMMENT 'The date by which the group organizer must submit individual passenger names (Pax names) for all seats in the confirmed block. Required for check-in, security compliance, and advance passenger information (API) submission.',
    `operating_carrier_code` STRING COMMENT 'Two-character IATA airline designator of the carrier actually operating the flight (relevant for codeshare blocks where the operating carrier may differ from the marketing carrier). Required for interline settlement and ACARS reporting.. Valid values are `^[A-Z0-9]{2}$`',
    `option_date` DATE COMMENT 'The deadline date by which the group organizer must confirm the number of seats and provide passenger names. If not confirmed by this date, the block may be automatically released back to inventory. Critical for inventory management and revenue optimization.',
    `overbooking_eligible` BOOLEAN COMMENT 'Indicates whether this group block is subject to overbooking controls. True = the block counts against overbooking limits; False = the block is protected from overbooking displacement (e.g., guaranteed allocation). Feeds revenue management overbooking models.',
    `reference` STRING COMMENT 'Externally-known alphanumeric reference code assigned to this group block by the Passenger Service System (PSS) or reservations team. Used by travel agents and group coordinators to identify and manage the block.. Valid values are `^[A-Z0-9]{6,20}$`',
    `remarks` STRING COMMENT 'Free-text remarks or special instructions associated with this group block, entered by the reservations agent or group coordinator. May include special service requests (SSR), handling notes, or commercial conditions.',
    `sales_channel` STRING COMMENT 'The distribution channel through which the group block was requested and booked. direct = airline reservations team; gds = Global Distribution System (GDS) such as Amadeus or Sabre; online_travel_agency = OTA; corporate = corporate travel desk; charter = charter operator.. Valid values are `direct|gds|online_travel_agency|corporate|charter`',
    `seats_blocked` STRING COMMENT 'Current number of seats held (blocked) in inventory for this group. Reduces available seat count for individual sale. May differ from seats_requested if the airline partially approved the block.',
    `seats_confirmed` STRING COMMENT 'Number of seats within the block that have been formally confirmed by the group organizer. May be less than seats_blocked during the tentative phase. Drives revenue recognition and ticketing obligations.',
    `seats_released` STRING COMMENT 'Number of seats that have been released back to general inventory from this group block, either due to partial cancellation, reduction, or expiry of the option. Supports inventory reconciliation.',
    `seats_requested` STRING COMMENT 'Total number of seats originally requested by the group organizer at the time of the initial group block request. Baseline for tracking changes to the block size.',
    `seats_ticketed` STRING COMMENT 'Number of seats within the confirmed block for which electronic tickets (e-tickets) have been issued. Used to track ticketing progress against the ticketing deadline.',
    `ticketing_deadline` DATE COMMENT 'The final date by which all confirmed seats in the group block must be ticketed (e-tickets issued). Failure to ticket by this date may result in automatic cancellation of unticketed seats and release to general inventory.',
    CONSTRAINT pk_group_block PRIMARY KEY(`group_block_id`)
) COMMENT 'Master entity representing a reserved seat block allocated to a group booking request on a specific flight-date and cabin. Captures the group name, number of seats blocked, option date (deadline for confirmation), ticketing deadline, applicable fare class, deposit status, and the linked PNR reference. Group blocks reduce available inventory for individual sale and must be tracked separately from regular fare class bucket availability.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`waitlist_entry` (
    `waitlist_entry_id` BIGINT COMMENT 'Unique surrogate identifier for each waitlist entry record in the AltĂ©a Inventory waitlist processing engine. Primary key for this data product.',
    `campaign_response_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign_response. Business justification: Passengers may waitlist after responding to a campaign offer when inventory is sold out. Airlines track campaign-driven demand including waitlisted requests for demand forecasting. Essential for measu',
    `fare_class_bucket_id` BIGINT COMMENT 'Reference to the specific fare class booking class bucket (e.g., Y, B, M, Q) for which availability was closed and the waitlist entry was created. Drives revenue management yield optimization.',
    `fare_class_id` BIGINT COMMENT 'Foreign key linking to revenue.fare_class. Business justification: Waitlist entries specify the requested fare class (RBD) for clearance processing. Waitlist clearance algorithms prioritize by fare class yield, eligibility rules, and bucket authorization. Essential f',
    `flight_inventory_id` BIGINT COMMENT 'Reference to the specific flight inventory record (flight-date-cabin combination) for which this waitlist entry is held. Identifies the sellable inventory unit in AltĂ©a Inventory.',
    `group_block_id` BIGINT COMMENT 'Reference to the group booking record when the waitlist entry originates from a group overflow scenario (waitlist_reason = GROUP_OVERFLOW). Links the individual waitlist entry back to the parent group contract for group management reporting.',
    `profile_id` BIGINT COMMENT 'Reference to the individual passenger profile associated with this waitlist entry. A single PNR may contain multiple passengers, each generating a separate waitlist entry.',
    `pnr_id` BIGINT COMMENT 'Reference to the Passenger Name Record (PNR) booking that is placed on the waitlist. Links the waitlist entry to the originating reservation in the Passenger Service System (PSS).',
    `altea_waitlist_sequence` STRING COMMENT 'Native waitlist sequence number assigned by the Amadeus AltĂ©a Inventory waitlist processing engine. Serves as the business identifier for this waitlist entry within the AltĂ©a system, used for reconciliation between the lakehouse Silver layer and the source PSS.',
    `booking_class` STRING COMMENT 'Single-letter IATA booking class (fare class) code within the requested cabin for which the waitlist entry was created (e.g., Y, B, M, H, Q, K, L, V, W, S, N, G). Directly maps to a revenue management fare class bucket in AltĂ©a Inventory.. Valid values are `^[A-Z]{1}$`',
    `cabin_code` STRING COMMENT 'IATA single-character cabin designator for the cabin class requested by the waitlisted passenger. F: First Class; C: Business Class; W: Premium Economy; Y: Economy. Determines the inventory pool from which clearance will be attempted.. Valid values are `F|C|W|Y`',
    `channel_code` STRING COMMENT 'Distribution channel through which the waitlist entry was created. GDS: Global Distribution System (e.g., Amadeus, Sabre, Travelport); NDC: IATA New Distribution Capability channel; DIRECT_WEB: airline direct website; MOBILE: airline mobile application; AIRPORT: airport check-in or gate agent; CALL_CENTER: reservations call center; INTERLINE: interline partner booking. [ENUM-REF-CANDIDATE: GDS|NDC|DIRECT_WEB|MOBILE|AIRPORT|CALL_CENTER|INTERLINE â€” promote to reference product]',
    `clearance_booking_class` STRING COMMENT 'The actual booking class in which the waitlist entry was cleared and confirmed, which may differ from the originally requested booking class if the revenue management system cleared the passenger into a higher-availability bucket. Null until clearance occurs.. Valid values are `^[A-Z]{1}$`',
    `clearance_method` STRING COMMENT 'Method by which the waitlist entry was cleared. AUTOMATIC: AltĂ©a Inventory engine cleared automatically when bucket availability opened; MANUAL: airport or reservations agent manually cleared the entry; UPGRADE_PROCESSING: cleared as part of an upgrade processing run; IROP_REACCOMMODATION: cleared during Irregular Operations (IROP) reaccommodation workflow.. Valid values are `AUTOMATIC|MANUAL|UPGRADE_PROCESSING|IROP_REACCOMMODATION`',
    `clearance_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when the waitlist entry was successfully cleared and the seat confirmed. Null if the entry has not yet been cleared. Used to measure waitlist clearance latency and revenue recovery timing. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when the waitlist entry was first created in the AltĂ©a Inventory system. Serves as the business event timestamp for queue ordering and audit purposes. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `destination_airport_code` STRING COMMENT 'Three-letter IATA airport code for the arrival airport of the waitlisted flight segment (e.g., LAX, CDG, SIN). Used for route-level waitlist analysis and GDS availability messaging.. Valid values are `^[A-Z]{3}$`',
    `expiry_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) at which the waitlist entry will automatically expire if not cleared, typically aligned with the flight departure time or a configurable pre-departure deadline set by revenue management policy. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `fare_basis_code` STRING COMMENT 'IATA fare basis code associated with the waitlisted booking (e.g., YLOWUS, BAPUS21). Encodes the fare family, booking class, and applicable restrictions. Used by revenue management to validate clearance eligibility and by pricing to re-price upon confirmation.. Valid values are `^[A-Z0-9]{1,8}$`',
    `ffp_member_number` STRING COMMENT 'Frequent Flyer Program (FFP) membership number of the waitlisted passenger. Used to apply loyalty-based priority rules and to credit miles upon clearance and travel. Classified as confidential PII as it is a unique personal identifier.',
    `ffp_tier` STRING COMMENT 'Frequent Flyer Program (FFP) membership tier of the waitlisted passenger at the time of waitlist entry creation (e.g., NONE, SILVER, GOLD, PLATINUM, ELITE). Higher tiers receive elevated priority rank in the waitlist queue per revenue management policy.. Valid values are `NONE|SILVER|GOLD|PLATINUM|ELITE`',
    `flight_date` DATE COMMENT 'Scheduled local departure date of the flight for which the waitlist entry is held. Format: yyyy-MM-dd. Used for inventory snapshot reporting and waitlist aging analysis.',
    `flight_number` STRING COMMENT 'IATA flight number (carrier designator + numeric suffix, e.g., AA101) for the flight on which the waitlist entry is held. Denormalized from the flight inventory record for operational reporting and GDS availability messaging.. Valid values are `^[A-Z]{2}[0-9]{1,4}$`',
    `gds_queue_number` STRING COMMENT 'Queue number assigned by the Global Distribution System (GDS) for this waitlist entry, used to route clearance notifications back to the originating travel agent or booking system. Null for direct-channel bookings.',
    `is_codeshare` BOOLEAN COMMENT 'Indicates whether the waitlist entry is associated with a codeshare flight operation where the marketing carrier differs from the operating carrier. True: codeshare booking; False: own-metal operation. Affects inventory allotment rules and clearance authority.',
    `marketing_carrier_code` STRING COMMENT 'Two-character IATA airline designator of the carrier under whose flight number the ticket was sold (marketing carrier). For codeshare flights, this may differ from the operating carrier. Determines which inventory pool and allotment rules apply.. Valid values are `^[A-Z0-9]{2}$`',
    `notification_sent` BOOLEAN COMMENT 'Indicates whether a clearance or status-change notification has been dispatched to the passenger or booking agent following a waitlist status transition. True: notification sent; False: notification pending or not applicable. Supports DOT consumer notification compliance.',
    `notification_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when the clearance or status-change notification was dispatched to the passenger or booking agent. Null if no notification has been sent. Used for DOT consumer protection compliance reporting. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `operating_carrier_code` STRING COMMENT 'Two-character IATA airline designator of the carrier actually operating the flight (e.g., AA, BA, EK). Relevant for codeshare flights where the marketing carrier differs from the operating carrier.. Valid values are `^[A-Z0-9]{2}$`',
    `origin_airport_code` STRING COMMENT 'Three-letter IATA airport code for the departure airport of the waitlisted flight segment (e.g., JFK, LHR, DXB). Used for route-level waitlist analysis and GDS availability messaging.. Valid values are `^[A-Z]{3}$`',
    `priority_rank` STRING COMMENT 'Numeric rank of this waitlist entry within the queue for the same flight, cabin, and fare class bucket. Lower values indicate higher priority for clearance. Determined by AltĂ©a Inventory based on booking time, fare paid, and frequent flyer tier.',
    `revenue_management_override` BOOLEAN COMMENT 'Indicates whether a revenue management analyst manually overrode the standard AltĂ©a Inventory waitlist clearance rules for this entry (e.g., to prioritise a high-value passenger or honour a corporate contract). True: manual override applied; False: standard automated rules applied.',
    `seat_count_requested` STRING COMMENT 'Number of seats requested on the waitlist for this entry. For individual bookings this is typically 1; for group bookings this may be greater than 1. Determines the inventory units required for clearance.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record that originated this waitlist entry. Primarily ALTEA_INV (Amadeus AltĂ©a Inventory) but may include GDS source codes for externally originated waitlist requests. Used for data lineage and reconciliation in the Silver layer.. Valid values are `ALTEA_INV|ALTEA_RES|SABRE|WORLDSPAN|GALILEO|AMADEUS_GDS`',
    `ssr_codes` STRING COMMENT 'Comma-separated list of IATA Special Service Request (SSR) codes associated with the waitlisted passenger (e.g., WCHR, VGML, UMNR). These SSRs must be honoured upon clearance and seat assignment. Stored as a denormalized string for operational reference.',
    `ticket_number` STRING COMMENT '13-digit IATA electronic ticket (e-ticket) number associated with the waitlisted booking segment. Follows the IATA 13-digit format (3-digit airline code + 10-digit serial). May be null if the ticket has not yet been issued at the time of waitlist creation.. Valid values are `^[0-9]{13}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when the waitlist entry record was last modified in the source system, including status transitions, priority re-ranking, or clearance processing. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `upgrade_from_cabin_code` STRING COMMENT 'For upgrade-request waitlist entries, the cabin code of the originally booked cabin from which the passenger is requesting an upgrade (e.g., Y for Economy). Null for sold-out or group overflow waitlist reasons. Used by upgrade processing logic in AltĂ©a Inventory.. Valid values are `F|C|W|Y`',
    `waitlist_reason` STRING COMMENT 'Business reason why the passenger or booking was placed on the waitlist rather than confirmed. SOLD_OUT: requested fare class bucket was closed; UPGRADE_REQUEST: passenger requested cabin upgrade pending availability; GROUP_OVERFLOW: group booking exceeded available allotment; OVERBOOKING_CONTROL: revenue management overbooking limit reached; CODESHARE_ALLOTMENT: codeshare partner inventory allocation exhausted.. Valid values are `SOLD_OUT|UPGRADE_REQUEST|GROUP_OVERFLOW|OVERBOOKING_CONTROL|CODESHARE_ALLOTMENT`',
    `waitlist_status` STRING COMMENT 'Current lifecycle status of the waitlist entry as managed by the AltĂ©a Inventory waitlist processing engine. OPEN: actively queued awaiting availability; CLEARED: bucket opened and seat confirmed; CANCELLED: passenger or agent cancelled the waitlist request; EXPIRED: flight departed or deadline passed without clearance; REJECTED: system or revenue management rule prevented clearance.. Valid values are `OPEN|CLEARED|CANCELLED|EXPIRED|REJECTED`',
    CONSTRAINT pk_waitlist_entry PRIMARY KEY(`waitlist_entry_id`)
) COMMENT 'Transactional record of a passenger or booking placed on the waitlist for a specific fare class bucket when availability is closed. Captures the PNR reference, requested cabin and fare class, waitlist priority rank, waitlist reason (sold-out, upgrade request, group overflow), creation timestamp, and clearance status. Managed by AltĂ©a Inventorys waitlist processing engine and cleared automatically when bucket availability opens.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`upgrade_inventory` (
    `upgrade_inventory_id` BIGINT COMMENT 'Unique surrogate identifier for the upgrade inventory record. Primary key for the upgrade_inventory data product within the Amadeus AltĂ©a Inventory system.',
    `aircraft_type_id` BIGINT COMMENT 'Foreign key linking to fleet.aircraft_type. Business justification: Elite upgrade clearance algorithms determine upgrade seat pool size from aircraft types cabin configuration (business class seat count, lie-flat availability). Automated upgrade processing at departu',
    `cabin_class_id` BIGINT COMMENT 'Foreign key linking to inventory.cabin_class. Business justification: upgrade_inventory manages upgrades TO a target cabin class. cabin_class is the reference master for cabin definitions. This FK links upgrade inventory to the target cabin master. cabin_class_code is r',
    `catering_order_id` BIGINT COMMENT 'Foreign key linking to procurement.catering_order. Business justification: Upgrade clearances change cabin meal requirements post-catering cutoff. Catering must adjust premium meal counts when upgrades clear. Operational link ensures service delivery to upgraded passengers a',
    `flight_inventory_id` BIGINT COMMENT 'Foreign key linking to inventory.flight_inventory. Business justification: upgrade_inventory manages the pool of seats designated for upgrades on a specific flight-date. flight_inventory is the master inventory record for that flight-date. This FK establishes the natural par',
    `flight_leg_id` BIGINT COMMENT 'Reference to the specific flight instance (flight-date combination) for which this upgrade inventory pool is managed. Links to the flight operations domain.',
    `auto_upgrade_enabled` BOOLEAN COMMENT 'Indicates whether the system is configured to automatically process and clear eligible upgrade requests for this flight-cabin pool without manual agent intervention.',
    `bid_upgrade_max_price` DECIMAL(18,2) COMMENT 'Maximum monetary bid amount cap for a paid bid-upgrade auction seat in this cabin on this flight. Prevents outlier bids and anchors the auction ceiling for revenue management.',
    `bid_upgrade_min_price` DECIMAL(18,2) COMMENT 'Minimum monetary bid amount accepted for a paid bid-upgrade auction seat in this cabin on this flight. Expressed in the operating currency. Feeds ancillary revenue management.',
    `bid_upgrade_seats` STRING COMMENT 'Number of seats allocated to the paid bid-upgrade auction channel (e.g., Plusgrade or equivalent ancillary upgrade product). Feeds the ancillary services domain for revenue capture.',
    `clearance_cutoff_hours` STRING COMMENT 'Number of hours before scheduled departure at which upgrade clearance processing closes. After this threshold, no further upgrades are processed and remaining pool seats revert to general inventory.',
    `clearance_window_hours` STRING COMMENT 'Number of hours before scheduled departure at which the upgrade clearance processing window opens. Defines when the system begins auto-clearing eligible waitlisted upgrade requests.',
    `codeshare_upgrade_seats` STRING COMMENT 'Number of upgrade seats within the pool allocated to codeshare partner airline passengers. Governs interline and codeshare upgrade entitlements per bilateral agreements.',
    `confirmed_upgrades` STRING COMMENT 'Current count of upgrade seats that have been confirmed and assigned to passengers across all upgrade types. Used to compute remaining availability in real time.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this upgrade inventory record was first created in the system, typically at schedule publication or inventory initialization for the flight-date.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which bid upgrade prices are denominated (e.g., USD, EUR, GBP). Aligns with BSP settlement currency.. Valid values are `^[A-Z]{3}$`',
    `elite_upgrade_processing_order` STRING COMMENT 'Primary sort criterion used when sequencing elite FFP upgrade candidates from the waitlist. TIER_FIRST=highest loyalty tier processed first; FARE_FIRST=highest paid fare class first; CHECKIN_FIRST=earliest check-in time first; MILES_FIRST=highest accrued miles balance first.. Valid values are `TIER_FIRST|FARE_FIRST|CHECKIN_FIRST|MILES_FIRST`',
    `elite_upgrade_seats` STRING COMMENT 'Number of seats within the upgrade pool reserved exclusively for complimentary upgrades to elite-tier Frequent Flyer Program (FFP) members. Interfaces with Oracle Loyalty Cloud for tier eligibility.',
    `fare_class_eligibility` STRING COMMENT 'Pipe-delimited list of booking class (fare class bucket) codes whose holders are eligible for upgrade processing from this pool (e.g., Y|B|M|H). Aligns with Amadeus AltĂ©a fare class bucket configuration. [ENUM-REF-CANDIDATE: promote to reference product for full fare class list]',
    `inventory_snapshot_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent real-time availability snapshot for this upgrade inventory pool, as published to GDS and direct booking channels. Aligns with Amadeus AltĂ©a real-time availability feeds.',
    `inventory_status` STRING COMMENT 'Current lifecycle status of the upgrade inventory pool for this flight-cabin combination. OPEN=upgrades available for processing; CLOSED=no further upgrades accepted; WAITLIST=pool exhausted but waitlist active; SUSPENDED=temporarily halted by revenue management; EXPIRED=clearance window has passed.. Valid values are `OPEN|CLOSED|WAITLIST|SUSPENDED|EXPIRED`',
    `last_clearance_run_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent automated upgrade clearance processing run for this flight-cabin pool. Used for operational monitoring and audit of clearance execution.',
    `load_factor_at_snapshot` DECIMAL(18,2) COMMENT 'Cabin load factor (percentage of seats filled) in the target upgrade cabin at the time of the most recent inventory snapshot. Expressed as a percentage (0.00â€“100.00). Used by revenue management to calibrate upgrade pool sizing.',
    `min_elite_tier_required` STRING COMMENT 'Minimum Frequent Flyer Program (FFP) elite tier level a member must hold to be eligible for a complimentary upgrade from this pool. Tiers below this threshold are excluded from elite upgrade processing.. Valid values are `SILVER|GOLD|PLATINUM|DIAMOND`',
    `notes` STRING COMMENT 'Free-text operational notes entered by revenue management or inventory control staff regarding special handling instructions, exceptions, or context for this upgrade inventory pool.',
    `operational_upgrade_seats` STRING COMMENT 'Number of seats held for operational upgrades issued by the airline at check-in or gate (e.g., IROP recovery, oversell resolution, VIP handling). Managed by ground operations and airport staff.',
    `overbooking_buffer_seats` STRING COMMENT 'Number of additional upgrade seats held as an overbooking buffer above physical cabin capacity to account for expected no-shows and cancellations. Managed by revenue management yield optimization.',
    `override_reason_code` STRING COMMENT 'Standardized reason code explaining why a revenue management override was applied to this upgrade inventory pool. Applicable only when revenue_management_override is TRUE. IROP=Irregular Operations; VIP=VIP passenger handling; COMMERCIAL=commercial agreement; CAPACITY_CHANGE=aircraft swap or gauge change.. Valid values are `IROP|VIP|COMMERCIAL|CAPACITY_CHANGE|PARTNER_REQUEST|OTHER`',
    `pool_closed_timestamp` TIMESTAMP COMMENT 'Timestamp at which the upgrade inventory pool was closed, either by reaching the clearance cutoff or by manual revenue management action. Null if pool is still open.',
    `pool_open_timestamp` TIMESTAMP COMMENT 'Timestamp at which the upgrade inventory pool was opened and made available for upgrade request intake. Marks the start of the upgrade acceptance window.',
    `priority_rule_code` STRING COMMENT 'Code referencing the upgrade priority rule set applied to this inventory pool. Governs the sequencing logic for elite FFP tier, fare class paid, check-in time, and other tiebreaker criteria.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `revenue_management_override` BOOLEAN COMMENT 'Indicates whether a revenue management analyst has manually overridden the system-calculated upgrade seat allocation for this flight-cabin pool, superseding automated yield optimization rules.',
    `source_cabin_class_code` STRING COMMENT 'IATA cabin class code of the originating cabin from which passengers are being upgraded. Defines the upgrade direction (e.g., Yâ†’C means Economy to Business). Complements cabin_class_code which is the target cabin.. Valid values are `F|C|W|Y`',
    `total_upgrade_seats` STRING COMMENT 'Total number of seats in the target cabin designated as available for upgrade processing across all upgrade types (elite FFP, bid, operational). This is the gross pool before allocation by upgrade type.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this upgrade inventory record, including seat count adjustments, status changes, or override actions.',
    `waitlisted_upgrades` STRING COMMENT 'Number of upgrade requests currently on the waitlist for this flight-cabin pool, pending seat availability or clearance processing.',
    CONSTRAINT pk_upgrade_inventory PRIMARY KEY(`upgrade_inventory_id`)
) COMMENT 'Master entity managing the pool of seats designated for complimentary and paid upgrade processing within a cabin on a specific flight-date. Captures the number of seats held for elite FFP upgrades, bid-upgrade auction seats, operational upgrade pool, upgrade priority rules, and the clearance window (hours before departure). Interfaces with the loyalty domain for elite tier upgrade prioritization and the ancillary domain for paid upgrade products.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`irop_reprotection` (
    `irop_reprotection_id` BIGINT COMMENT 'Unique surrogate identifier for each IROP reprotection action record in the inventory system. Primary key for this transactional entity.',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Operations Control Center staff authorize IROP passenger reprotections and inventory ring-fencing. Required for operational accountability, regulatory compliance audit trails (EU261, DOT), and cost ce',
    `cabin_class_id` BIGINT COMMENT 'Foreign key linking to inventory.cabin_class. Business justification: irop_reprotection records inventory reprotection actions targeting a specific cabin class during irregular operations. cabin_class is the reference master for cabin definitions. This FK links reprotec',
    `catering_order_id` BIGINT COMMENT 'Foreign key linking to procurement.catering_order. Business justification: IROP events trigger catering order cancellations for disrupted flights and adjustments for recovery flights. Operations Control Center uses this link to manage catering changes during irregular operat',
    `consumer_protection_case_id` BIGINT COMMENT 'Foreign key linking to compliance.consumer_protection_case. Business justification: IROP reprotection events that trigger passenger rights obligations (EU261 delay/cancellation compensation, DOT tarmac delay) must link to consumer protection cases for compensation tracking, regulator',
    `cost_centre_id` BIGINT COMMENT 'Foreign key linking to finance.cost_centre. Business justification: IROP recovery costs (passenger compensation, rebooking, hotel vouchers) are tracked by cost center for financial impact analysis and operational performance reporting. Airlines monitor IROP cost expos',
    `fare_class_bucket_id` BIGINT COMMENT 'Foreign key linking to inventory.fare_class_bucket. Business justification: irop_reprotection records target a specific fare class bucket for reprotection. fare_class_bucket is the master entity for RBD buckets. This FK links reprotection records to the bucket master. fare_cl',
    `flight_irop_event_id` BIGINT COMMENT 'Reference to the parent IROP event (e.g., cancellation, diversion, significant delay) that triggered this reprotection action. Links to the IROP event master record.',
    `scheduled_flight_id` BIGINT COMMENT 'Reference to the original flight segment that was disrupted (cancelled, diverted, or significantly delayed), causing the need for passenger reprotection. Directly impacts inventory on the disrupted flight.',
    `authorized_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when the Operations Control Center (OCC) formally authorized this reprotection action. Represents the principal business event time for this transaction.',
    `codeshare_indicator` BOOLEAN COMMENT 'Indicates whether the recovery flight operates under a codeshare agreement. When true, inventory ring-fencing must be coordinated with the operating carriers inventory system, adding complexity to the reprotection process.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when this reprotection record was first created in the inventory system. Audit trail field for data lineage and compliance.',
    `destination_airport_iata_code` STRING COMMENT 'Three-letter IATA airport code for the arrival airport of the disrupted flight (e.g., LAX, CDG). Denormalized for IROP reporting and route-level disruption analysis.. Valid values are `^[A-Z]{3}$`',
    `disrupted_flight_date` DATE COMMENT 'Scheduled departure date (local airport time) of the disrupted flight. Used for day-of-operations reporting and IROP timeline analysis.',
    `disrupted_flight_number` STRING COMMENT 'IATA flight number of the disrupted flight (e.g., AA1234). Denormalized for operational reporting and IROP dashboards without requiring a join to the flight segment table.. Valid values are `^[A-Z0-9]{2,3}[0-9]{1,4}[A-Z]?$`',
    `downgrade_compensation_applicable` BOOLEAN COMMENT 'Indicates whether passengers in this reprotection block are entitled to downgrade compensation (e.g., fare difference refund or EMD issuance) because they are being accommodated in a lower cabin class than originally booked.',
    `gds_availability_updated` BOOLEAN COMMENT 'Indicates whether the real-time availability snapshot on the recovery flight has been updated and broadcast to GDS channels (e.g., Amadeus, Sabre, Travelport) to reflect the ring-fenced seats. Critical for preventing oversell on the recovery flight.',
    `interline_reprotection_indicator` BOOLEAN COMMENT 'Indicates whether this reprotection action involves rebooking passengers onto a flight operated by a different carrier under an interline agreement. Triggers BSP/ARC settlement and interline billing processes.',
    `inventory_impact_acknowledged` BOOLEAN COMMENT 'Indicates whether the Revenue Management system has acknowledged and processed the inventory reduction on the recovery flight caused by this reprotection action. Ensures yield optimization models reflect the ring-fenced seats.',
    `irop_cause_type` STRING COMMENT 'Classification of the root cause of the IROP event that triggered reprotection. Drives downstream analytics on disruption patterns and recovery cost attribution. [ENUM-REF-CANDIDATE: CANCELLATION|DIVERSION|SIGNIFICANT_DELAY|EQUIPMENT_SWAP|ATC_GROUND_STOP|WEATHER|CREW_SHORTAGE|SECURITY|MEDICAL|MECHANICAL â€” promote to reference product]. Valid values are `CANCELLATION|DIVERSION|SIGNIFICANT_DELAY|EQUIPMENT_SWAP|ATC_GROUND_STOP|WEATHER`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when this reprotection record was last modified. Tracks status changes, seat count adjustments, and authorization updates for audit purposes.',
    `occ_authorization_reference` BIGINT COMMENT 'Reference to the Operations Control Center authorization record that approved this reprotection action. Ensures accountability and traceability of inventory ring-fencing decisions.',
    `operating_carrier_code` STRING COMMENT 'Two-letter IATA airline designator code of the carrier actually operating the recovery flight. May differ from the marketing carrier in codeshare scenarios. Required for interline reprotection coordination.. Valid values are `^[A-Z0-9]{2,3}$`',
    `origin_airport_iata_code` STRING COMMENT 'Three-letter IATA airport code for the departure airport of the disrupted flight (e.g., JFK, LHR). Denormalized for IROP reporting and passenger communication workflows.. Valid values are `^[A-Z]{3}$`',
    `overbooking_override_applied` BOOLEAN COMMENT 'Indicates whether the OCC applied an overbooking override to accommodate reprotected passengers beyond the recovery flights standard authorized overbooking limit. Requires elevated authorization and triggers denied boarding risk monitoring.',
    `pax_displaced_count` STRING COMMENT 'Total number of passengers displaced by the IROP event who are eligible for reprotection under this action. May exceed seats_ring_fenced if partial reprotection is applied.',
    `pnr_count` STRING COMMENT 'Number of distinct Passenger Name Records (PNRs) included in this reprotection action. Used to track the scope of the reprotection and reconcile against seats_ring_fenced.',
    `priority_class` STRING COMMENT 'Priority tier assigned to this reprotection block, determining the order in which displaced passengers are accommodated on the recovery flight. ELITE: frequent flyer elite members; CONNECTING: passengers with onward connections at risk; MEDICAL: passengers with medical needs or SSR codes; UNACCOMPANIED_MINOR: UM passengers; STANDARD: general passengers.. Valid values are `ELITE|CONNECTING|MEDICAL|UNACCOMPANIED_MINOR|STANDARD`',
    `recovery_flight_date` DATE COMMENT 'Scheduled departure date (local airport time) of the recovery flight. Used to determine inventory impact window and reprotection timeline.',
    `recovery_flight_number` STRING COMMENT 'IATA flight number of the recovery (reprotection) flight on which seats are ring-fenced (e.g., AA1456). Denormalized for operational dashboards and GDS availability messaging.. Valid values are `^[A-Z0-9]{2,3}[0-9]{1,4}[A-Z]?$`',
    `release_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when unused ring-fenced seats were released back to general inventory. Populated when reprotection_status transitions to RELEASED or EXPIRED. Null if all seats were utilized or reprotection is still active.',
    `reprotection_notes` STRING COMMENT 'Free-text operational notes entered by the OCC agent describing special circumstances, exceptions, or instructions related to this reprotection action (e.g., VIP handling, diplomatic passengers, group reprotection conditions).',
    `reprotection_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned by the Passenger Service System (PSS) to uniquely identify this reprotection action across operational systems and GDS channels. Used for cross-system traceability.. Valid values are `^REPRO-[A-Z0-9]{8,16}$`',
    `reprotection_status` STRING COMMENT 'Current lifecycle state of the reprotection action. PENDING: awaiting OCC authorization; ACTIVE: seats ring-fenced and available for displaced passengers; CONFIRMED: passengers booked onto recovery flight; RELEASED: unused seats returned to general inventory; EXPIRED: reprotection window passed without use; CANCELLED: reprotection voided.. Valid values are `PENDING|ACTIVE|CONFIRMED|RELEASED|EXPIRED|CANCELLED`',
    `reprotection_type` STRING COMMENT 'Classification of the reprotection strategy applied. SAME_DAY: recovery on same calendar day; NEXT_DAY: recovery on following day; MULTI_LEG: recovery requires multiple connecting flights; INTERLINE: recovery on partner carrier; UPGRADE: passenger accommodated in higher cabin; DOWNGRADE: passenger accommodated in lower cabin with compensation.. Valid values are `SAME_DAY|NEXT_DAY|MULTI_LEG|INTERLINE|UPGRADE|DOWNGRADE`',
    `reprotection_window_close_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when the reprotection inventory block expires. After this time, unused ring-fenced seats are released back to general inventory. Nullable if the window is open-ended until flight departure.',
    `reprotection_window_open_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when the reprotection inventory block was activated and seats became available for displaced passenger booking. Marks the start of the reprotection window.',
    `seats_released` STRING COMMENT 'Number of ring-fenced seats that were released back to general inventory after the reprotection window closed or the action was cancelled. Equals seats_ring_fenced minus seats_utilized when fully resolved.',
    `seats_ring_fenced` STRING COMMENT 'Number of seats on the recovery flight that have been ring-fenced (blocked from general sale) for displaced passengers under this reprotection action. Directly reduces available inventory on the recovery flight.',
    `seats_utilized` STRING COMMENT 'Number of ring-fenced seats that were actually used by displaced passengers. Compared against seats_ring_fenced to measure reprotection efficiency and inventory recovery.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record that originated this reprotection record. ALTEA: Amadeus AltĂ©a Inventory PSS; NETLINE: Lufthansa Systems NetLine/Ops; SABRE: Sabre AirVision; MANUAL: manually entered by OCC agent. Used for data lineage and reconciliation.. Valid values are `ALTEA|NETLINE|SABRE|MANUAL`',
    `ssr_codes` STRING COMMENT 'Comma-separated list of IATA four-letter Special Service Request (SSR) codes applicable to passengers in this reprotection block (e.g., WCHR, UMNR, MEDA). Ensures special handling requirements are preserved during reprotection.. Valid values are `^[A-Z]{4}(,[A-Z]{4})*$`',
    CONSTRAINT pk_irop_reprotection PRIMARY KEY(`irop_reprotection_id`)
) COMMENT 'Transactional record of inventory reprotection actions taken during IROP (Irregular Operations) events such as flight cancellations, diversions, or significant delays. Captures the disrupted flight reference, the reprotection flight(s) offered, number of seats ring-fenced for displaced passengers, priority class (elite, connecting, medical), reprotection status, and the operations control center authorization. Directly impacts available inventory on recovery flights.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`season_inventory_plan` (
    `season_inventory_plan_id` BIGINT COMMENT 'Unique surrogate identifier for the seasonal inventory plan record. Primary key for this entity in the Silver Layer lakehouse.',
    `aircraft_type_id` BIGINT COMMENT 'Foreign key linking to fleet.aircraft_type. Business justification: Strategic network planning allocates aircraft types to seasonal routes based on fleet composition, range capability, and seat capacity. Season inventory plans drive schedule filings and slot coordinat',
    `budget_plan_id` BIGINT COMMENT 'Foreign key linking to finance.budget_plan. Business justification: Seasonal capacity plans (ASK, frequencies, aircraft deployment) are budgeted in financial planning cycles. Links planned inventory to revenue/cost budgets for variance analysis and board reporting. Co',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Seasonal marketing campaigns are planned against seasonal inventory plans (summer schedules, winter routes). Integrated commercial planning requires alignment between capacity deployment and marketing',
    `fuel_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.fuel_contract. Business justification: Seasonal flight programs determine fuel contract volumes and airport coverage requirements. Fuel procurement uses seasonal plans for contract negotiations, minimum offtake commitments, and supplier se',
    `route_id` BIGINT COMMENT 'Reference to the route master record for the origin-destination pair covered by this inventory plan. Enables route-level aggregation and network planning analysis.',
    `schedule_season_id` BIGINT COMMENT 'Reference to the flight schedule record from which this seasonal inventory plan was derived. Links the inventory plan to the underlying schedule planning entity (route, frequency, and timing) as defined in the schedule planning system.',
    `supply_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.supply_contract. Business justification: Seasonal capacity plans drive long-term catering and ground service contracts. Procurement negotiates seasonal supply contracts based on planned flight programs. Essential for contract volume commitme',
    `approved_by` STRING COMMENT 'Name or employee identifier of the Revenue Management or Inventory Control authority who formally approved this seasonal inventory plan for activation. Supports audit trail and governance requirements.',
    `approved_date` DATE COMMENT 'The date on which this seasonal inventory plan was formally approved by the authorized Revenue Management or Inventory Control authority. Represents the BUSINESS_EVENT_TIMESTAMP for the approval milestone.',
    `authorized_capacity` STRING COMMENT 'Total number of bookings authorized for acceptance on this flight for the season, incorporating the overbooking strategy applied to total_planned_capacity. This is the effective sellable inventory ceiling used by the Passenger Service System.',
    `business_class_capacity` STRING COMMENT 'Number of seats planned in the Business Class cabin (including premium business variants such as Clipper Class, Club World) for this seasonal inventory plan. Zero if no Business Class cabin exists.',
    `codeshare_allocation_seats` STRING COMMENT 'Number of seats within the total authorized capacity allocated to codeshare marketing partners for sale under their own flight numbers. Null or zero if codeshare_indicator is False.',
    `codeshare_indicator` BOOLEAN COMMENT 'Flag indicating whether this inventory plan includes codeshare seat allocations (True) or is a purely operating-carrier plan (False). When True, codeshare partner allocations are governed by this plan.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this seasonal inventory plan record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Serves as RECORD_AUDIT_CREATED for audit trail purposes.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which yield targets and revenue metrics for this inventory plan are denominated (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `days_of_operation` STRING COMMENT 'IATA SSIM-standard days-of-week string indicating which days this flight operates within the season (e.g., 1234567 = daily, 135 = Mon/Wed/Fri). Uses IATA day numbering: 1=Monday through 7=Sunday.. Valid values are `^[1-7]{1,7}$`',
    `destination_airport_code` STRING COMMENT 'Three-letter IATA airport code for the arrival station of the flight covered by this inventory plan (e.g., JFK, CDG). Used to identify the route destination.. Valid values are `^[A-Z]{3}$`',
    `economy_class_capacity` STRING COMMENT 'Number of seats planned in the Economy Class cabin for this seasonal inventory plan. Typically the largest cabin and primary driver of load factor and yield management decisions.',
    `first_class_capacity` STRING COMMENT 'Number of seats planned in the First Class cabin for this seasonal inventory plan. Zero if the aircraft configuration does not include a First Class cabin.',
    `flight_number` STRING COMMENT 'IATA-format operating flight number (carrier designator + numeric suffix, e.g., AA101) for which this seasonal inventory plan is defined. Identifies the specific flight or flight series covered by this plan.. Valid values are `^[A-Z0-9]{2}[0-9]{1,4}$`',
    `gds_availability_indicator` BOOLEAN COMMENT 'Flag indicating whether this flights inventory is made available for sale through Global Distribution Systems (GDS) such as Amadeus, Sabre, and Travelport (True) or is restricted to direct channels only (False).',
    `iata_season_code` STRING COMMENT 'IATA-standard season designator indicating the schedule period this plan covers. Format: S=Summer, W=Winter followed by 2-digit year (e.g., S24 for Summer 2024, W24 for Winter 2024). Aligns with IATA SSIM season definitions.. Valid values are `^[SW][0-9]{2}$`',
    `initial_bucket_authorization` STRING COMMENT 'Serialized representation of the initial booking class (fare bucket) authorization levels at season open, as configured in Amadeus AltĂ©a Inventory (e.g., Y:180,B:120,M:90,Q:60,V:30). Defines the starting inventory allocation across RBD (Reservation Booking Designator) buckets before dynamic RM optimization. Confidential as it encodes pricing strategy. [ENUM-REF-CANDIDATE: promote bucket detail to a child product season_inventory_bucket_plan â€” promote to reference product]',
    `interline_indicator` BOOLEAN COMMENT 'Flag indicating whether this flight and its inventory plan participates in interline ticketing agreements with other carriers (True) or is restricted to own-carrier ticketing only (False).',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this seasonal inventory plan record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Serves as RECORD_AUDIT_UPDATED for change tracking and data lineage.',
    `load_factor_target` DECIMAL(18,2) COMMENT 'The target load factor (percentage of seats filled) set by Revenue Management for this flight during the season, expressed as a percentage (e.g., 85.00 = 85%). Used as the baseline KPI against which actual load factor performance is measured. Confidential as it reflects commercial strategy.',
    `marketing_carrier_code` STRING COMMENT 'Two-character IATA airline designator of the carrier marketing and selling seats on this flight. May differ from operating_carrier_code in codeshare arrangements. Null if same as operating carrier.. Valid values are `^[A-Z0-9]{2}$`',
    `minimum_connecting_time_minutes` STRING COMMENT 'Minimum Connecting Time (MCT) in minutes applicable at the origin airport for this flight, as published for the season. Used by GDS and booking systems to validate connection feasibility for itinerary construction.',
    `operating_carrier_code` STRING COMMENT 'Two-character IATA airline designator of the carrier actually operating the flight (e.g., AA, BA, LH). Distinguishes the operating carrier from marketing carriers in codeshare arrangements.. Valid values are `^[A-Z0-9]{2}$`',
    `origin_airport_code` STRING COMMENT 'Three-letter IATA airport code for the departure station of the flight covered by this inventory plan (e.g., LHR, JFK). Used to identify the route origin.. Valid values are `^[A-Z]{3}$`',
    `overbooking_rate` DECIMAL(18,2) COMMENT 'The planned overbooking percentage applied to total capacity for this seasonal inventory plan, expressed as a percentage above 100% (e.g., 5.00 means 5% overbooking above physical capacity). Set by Revenue Management based on historical no-show and cancellation rates. Confidential as it reflects pricing strategy.',
    `plan_code` STRING COMMENT 'Externally-known alphanumeric business identifier for this seasonal inventory plan, used in Amadeus AltĂ©a Inventory and cross-system references (e.g., SIP-W24-LHR-JFK-Y). Serves as the BUSINESS_IDENTIFIER for this master resource.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `plan_name` STRING COMMENT 'Human-readable descriptive name for the seasonal inventory plan (e.g., Winter 2024 LHR-JFK Economy Inventory Plan). Serves as the IDENTITY_LABEL for this master resource.',
    `plan_status` STRING COMMENT 'Current lifecycle state of the seasonal inventory plan. draft = under construction; approved = authorized for use; active = currently governing live inventory; suspended = temporarily halted; closed = season ended; superseded = replaced by a revised plan. Serves as LIFECYCLE_STATUS.. Valid values are `draft|approved|active|suspended|closed|superseded`',
    `plan_type` STRING COMMENT 'Classification of the inventory plan by its operational purpose. baseline = initial seasonal plan; revised = updated mid-season plan; codeshare = plan governing codeshare inventory allocation; charter = charter flight inventory; adhoc = ad-hoc or supplemental plan. Serves as CLASSIFICATION_OR_TYPE.. Valid values are `baseline|revised|codeshare|charter|adhoc`',
    `planned_arrival_time` TIMESTAMP COMMENT 'Planned scheduled arrival time in local time at the destination airport, in HHMM format (e.g., 1145 for 11:45). Represents the published schedule time for the season as filed in IATA SSIM.',
    `planned_departure_time` TIMESTAMP COMMENT 'Planned scheduled departure time in local time at the origin airport, in HHMM format (e.g., 0830 for 08:30). Represents the published schedule time for the season as filed in IATA SSIM.',
    `premium_economy_capacity` STRING COMMENT 'Number of seats planned in the Premium Economy cabin for this seasonal inventory plan. Zero if no Premium Economy cabin exists on the planned aircraft type.',
    `revenue_management_system_code` STRING COMMENT 'The identifier assigned to this inventory plan within the Sabre AirVision Revenue Management system. Used for cross-system traceability between the inventory plan in AltĂ©a and the corresponding RM optimization model in Sabre AirVision.',
    `season_end_date` DATE COMMENT 'The last date of the IATA schedule season for which this inventory plan is effective. Corresponds to the IATA SSIM-defined season end date. Serves as EFFECTIVE_UNTIL.',
    `season_start_date` DATE COMMENT 'The first date of the IATA schedule season for which this inventory plan is effective. Corresponds to the IATA SSIM-defined season start date (typically last Sunday of March for Summer, last Sunday of October for Winter). Serves as EFFECTIVE_FROM.',
    `total_planned_capacity` STRING COMMENT 'Total number of sellable seats planned for this flight for the season, across all cabins. Represents the principal quantitative capacity fact (MEASUREMENT_OR_VALUE) for this inventory plan. Derived from aircraft configuration but stored here as the authoritative planned figure.',
    `yield_target` DECIMAL(18,2) COMMENT 'The target yield (revenue per Revenue Passenger Kilometer â€” RPK) set by Revenue Management for this flight for the season, expressed in the operating currency per RPK. Used as the baseline revenue efficiency target. Confidential as it encodes pricing strategy.',
    CONSTRAINT pk_season_inventory_plan PRIMARY KEY(`season_inventory_plan_id`)
) COMMENT 'Master entity representing the pre-departure seasonal inventory plan for a flight or route, defining the planned capacity deployment, cabin mix, initial bucket authorization levels, and overbooking strategy for an IATA season (summer/winter schedule period). Created during schedule planning and used as the baseline against which actual inventory performance is measured. Aligns with IATA SSIM season definitions.';

CREATE OR REPLACE TABLE `airlines_ecm`.`inventory`.`lease_cost_allocation` (
    `lease_cost_allocation_id` BIGINT COMMENT 'Unique surrogate identifier for the lease cost allocation record',
    `flight_inventory_id` BIGINT COMMENT 'Foreign key linking to the flight inventory record receiving the allocated lease cost',
    `journal_entry_id` BIGINT COMMENT 'Reference to the SAP S/4HANA general ledger journal entry document generated from this allocation record. Supports audit trail and reconciliation between cost allocation system and financial ledger.',
    `lease_contract_id` BIGINT COMMENT 'Foreign key linking to the lease contract from which costs are being allocated',
    `allocation_method` STRING COMMENT 'Methodology used to allocate lease costs to this flight. FLIGHT_HOURS: proportional to block hours; CYCLE_COUNT: proportional to takeoff/landing cycles; REVENUE_SHARE: proportional to revenue generated; SEAT_MILES: proportional to available seat miles; MANUAL: finance-approved override allocation.',
    `allocation_percentage` DECIMAL(18,2) COMMENT 'Percentage of the lease contracts periodic cost allocated to this specific flight inventory record, expressed as a decimal (e.g., 0.0125 = 1.25%). Sum of allocation percentages across all flights for a given lease-period should equal 1.0.',
    `allocation_period` STRING COMMENT 'Accounting period (YYYY-MM format) for which this lease cost allocation applies. Supports monthly close processes and period-over-period cost variance analysis.',
    `allocation_status` STRING COMMENT 'Lifecycle status of the allocation record. DRAFT: preliminary calculation; APPROVED: finance-reviewed and approved; POSTED: GL journal entries generated; REVERSED: allocation reversed due to correction or schedule change.',
    `amount` DECIMAL(18,2) COMMENT 'Monetary amount of lease expense allocated to this flight inventory record for the effective period, denominated in the lease contract currency. Calculated as periodic_lease_payment Ă— allocation_percentage, adjusted for any variable payment components.',
    `approved_by` STRING COMMENT 'User ID or employee identifier of the finance analyst or manager who approved this allocation for posting to the general ledger.',
    `approved_timestamp` TIMESTAMP COMMENT 'Timestamp when this allocation record was approved for GL posting.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this allocation record was initially created by the lease cost allocation batch process or manual entry.',
    `effective_date` DATE COMMENT 'Date from which this lease cost allocation is effective. Typically aligns with the flight departure date or the beginning of the accounting period for which costs are being allocated.',
    `flight_hours_attributed` DECIMAL(18,2) COMMENT 'Block hours (departure gate to arrival gate) attributed to this flight for the purpose of lease cost allocation. Used in utilization-based allocation methods where lease cost is distributed proportionally to flight hours operated.',
    CONSTRAINT pk_lease_cost_allocation PRIMARY KEY(`lease_cost_allocation_id`)
) COMMENT 'This association product represents the allocation of aircraft lease contract costs to specific flight inventory records for IFRS 16 compliance, route profitability analysis, and unit cost accounting. Each record links one lease contract to one flight-date inventory record, capturing the proportion of lease expense, flight hours attributed, allocation methodology, and effective period. This enables accurate P&L attribution at the flight level and supports revenue management yield optimization decisions.. Existence Justification: Airlines operate under IFRS 16 lease accounting requirements that mandate allocation of aircraft lease costs to individual flight operations for accurate unit cost accounting and route profitability analysis. A single lease contract (covering an aircraft, engine, or APU) generates costs that must be allocated across hundreds or thousands of flight inventory records over the lease term, while a single flight may consume resources from multiple leased assets (primary aircraft lease, spare engine lease, APU lease). The allocation relationship is actively managed by finance teams who calculate, approve, and post allocation entries monthly, with specific allocation percentages, flight hours, cost amounts, and methodology tracked for each lease-flight pairing.';

